t;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;max&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;probs&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;96&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;97&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; sklearn&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;decomposition &lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; PCA&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;98&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; matplotlib&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;pyplot &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; plt&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;99&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;100&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;all_features &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; torch&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;cat&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;image_features&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; text_features&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; dim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;cpu&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;numpy&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;101&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;102&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;pca &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; PCA&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;n_components&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;103&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;features_2d &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; pca&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;fit_transform&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;all_features&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;104&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;105&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;figure&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;figsize&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;106&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;scatter&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;features_2d&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; features_2d&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; color&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;red&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; label&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;Image Feature&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;107&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; i&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; text &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;enumerate&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;my_text&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;108&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;scatter&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;features_2d&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; features_2d&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; label&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string-interpolation&#34;&gt;&lt;span class=&#34;token string&#34;&gt;f&#39;Text Feature: &lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;text&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;109&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;110&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;legend&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;111&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;title&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;PCA of Image and Text Features&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;112&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;xlabel&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;PCA Component 1&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;113&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;ylabel&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;PCA Component 2&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;114&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;show&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;h1 id=&#34;我的科研杂谈&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#我的科研杂谈&#34;&gt;#&lt;/a&gt; 我的科研杂谈&lt;/h1&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;分享一些，在科研中随感所想的东西。受主观因素以及本人所在科研环境条件的影响，相关观点仅供参考。甚至一些观点可能随着时间的推移而落后，我也会相应地纠正过来。&lt;/p&gt;
&lt;/div&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;2025-02-09&lt;/code&gt; ：如何做出有价值的工作？我的第一篇工作是失败的，毫无创新可言，实验效果也很差，但是为我积累了丰富的科研经验。在放弃第一篇工作后，第二篇工作仅在 2 周的时间内就实现了 &lt;code&gt;idea&lt;/code&gt;  的确定，仅在 2 个月内就进入了论文初稿的撰写，实验结果还是可以说得过去。我并没有取低光照图像增强领域的 &lt;code&gt;SOTA&lt;/code&gt;  作为 &lt;code&gt;baseline&lt;/code&gt; ，而是阅读了其他领域的方法，将其他领域的思想和方法结合，然后应用到低光领域。这种做法需要较为熟练的代码能力，而且较难做出高的实验分数，可能需要不断地更换其他领域的思想和方法。这种做法并不基于本领域的现有 &lt;code&gt;SOTA&lt;/code&gt;  方法，能够避开与现有 &lt;code&gt;SOTA&lt;/code&gt;  方法的比较。如果你的思想方法是本领域没有出现的（需要彻查），那么作为开创工作大胆发 &lt;code&gt;paper&lt;/code&gt;  即可。如果有若干个相关工作，可以与他们进行对比，超越即可。这可以大大降低了实验分数的压力。但是如果想要追求与更高的分数如 &lt;code&gt;SOTA&lt;/code&gt;  的对比，就不太容易，因为这一方面需要优秀的科研直觉、强大代码能力、不错的运气。如果运气好，你结合了其他领域的思想方法正好极其 &lt;code&gt;SOTA&lt;/code&gt; ，那么完全可以投高水平期刊和会议，甚至顶会顶刊。所以也有另一种方法，就是以本领域的 &lt;code&gt;SOTA&lt;/code&gt;  工作的方法为 &lt;code&gt;baseline&lt;/code&gt; ，结合其他领域的思想和方法。这种方式的实验分数普遍偏高，但是会经常见到自己的实验效果反而比 &lt;code&gt;SOTA&lt;/code&gt;  低的现象，因此主要和所参考的本领域 &lt;code&gt;SOTA&lt;/code&gt;  对比，超越之较难。虽然说超越较难，但是一旦超越了，高的实验分数确实可以作为一个不错的亮点。然而，如果以本领域的 &lt;code&gt;SOTA&lt;/code&gt;  方法为 &lt;code&gt;baseline&lt;/code&gt; （也就是已经以该 &lt;code&gt;SOTA&lt;/code&gt;  方法的代码为模板），最终的模型结构会与该 &lt;code&gt;SOTA&lt;/code&gt;  方法较为相似，内行人一看就知道来源于哪篇工作，因此即使有较高的实验分数，想要发高水平期刊和会议还是因为创新点较为雷同而被拒。两种方式各有特点，他们难点不同，前者难在结合其他领域的思想，后者难在超越本领域 &lt;code&gt;SOTA&lt;/code&gt; 。他们发 &lt;code&gt;paper&lt;/code&gt;  的标志不同，前者只要超过相关工作即可，后者需要超过 &lt;code&gt;SOTA&lt;/code&gt; 。他们的 &lt;code&gt;baseline&lt;/code&gt;  不同，前者的 &lt;code&gt;baseline&lt;/code&gt;  是其他领域的思想方法在本领域的效果（一般较低），后者的 &lt;code&gt;baseline&lt;/code&gt;  是本领域的 &lt;code&gt;SOTA&lt;/code&gt; （一般较高）。他们证明自己有效的方式是一致的，都需要超越 &lt;code&gt;baseline&lt;/code&gt; ，才能证明自己的工作有效。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;2025-02-13&lt;/code&gt; ：其实可以为读过的每一篇论文用自己的理解提炼出关键思想，甚至可以用英文写，这样也有助于语感的保持。或者把自己对这篇论文的主要思考用英文记录。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;2025-03-06&lt;/code&gt; ：最近做 &lt;code&gt;MAI2025&lt;/code&gt;  实验不顺，于是逛知乎刷到一个贴子。贴主说，既然是从 &lt;code&gt;baseline&lt;/code&gt;  上进行实现自己的 &lt;code&gt;idea&lt;/code&gt; 、优化改进，那么不一定要直接把 &lt;code&gt;idea&lt;/code&gt;  的一整个 &lt;code&gt;backbone&lt;/code&gt;  的代码都搭建好，可以考虑往 &lt;code&gt;baseline&lt;/code&gt;  的 &lt;code&gt;backbone&lt;/code&gt;  上需要实现 &lt;code&gt;idea&lt;/code&gt;  的地方施加一些与自己 &lt;code&gt;idea&lt;/code&gt;  相关的扰动。这些扰动添加进去后，本质上是往自己的 &lt;code&gt;idea&lt;/code&gt;  上靠拢的一小步。如果这些小扰动可以让模型的性能发生较显著的提升，那么说明这种改进是很有效果的，那么就可以进一步扩大同种类型的这种改进。如果连这些小扰动、小修改都无法让模型的性能发生显著的提升，甚至是下降，说明这个小改进并不 &lt;code&gt;work&lt;/code&gt; ，甚至是整个 &lt;code&gt;idea&lt;/code&gt;  并不 &lt;code&gt;work&lt;/code&gt; ，那就没必要扩展到一整个 &lt;code&gt;backbone&lt;/code&gt; 。在我看来，这种小扰动、小修改本质上是 &lt;code&gt;idea&lt;/code&gt;  的小验证，这种小验证也可以算是一种小的消融实验，小的探索，这对于节省不必要的科研时间浪费是相当有借鉴意义的。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;2025-03-13&lt;/code&gt; ：从探索的实验中寻找问题是相当重要的事情。&lt;/li&gt;
&lt;/ul&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;h1 id=&#34;divergent-thinking&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#divergent-thinking&#34;&gt;#&lt;/a&gt;  &lt;code&gt;Divergent Thinking&lt;/code&gt;&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;Danger&lt;/code&gt; ！ &lt;code&gt;Danger&lt;/code&gt; ！ &lt;code&gt;Secret&lt;/code&gt; ！ &lt;code&gt;Secret&lt;/code&gt; ！&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h5 id=&#34;zs-n2n&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#zs-n2n&#34;&gt;#&lt;/a&gt;  &lt;code&gt;ZS-N2N&lt;/code&gt;&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;Their downsampling operation just first divided the original image into non-overlapping patches with each size is 2 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\times&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;×&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 2. Is there a possibility, we could use a cascading network to denoise low light image, which divided the input image with patch size is 2 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\times&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;×&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 2 at first level and then processed the image for denoising. In next level, the network divided the input image with patch size  is 4 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\times&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;×&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 4. And so on?&lt;/li&gt;
&lt;li&gt;Is there a possibility, we could change the downsampling operation before using 2 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\times&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;×&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 2 convolution kernel process the downsampling patches?&lt;/li&gt;
&lt;li&gt;Is there a possibility, we could use the two downsampling patches as PairLIE’s input and constructed P-Net, L-Net, R-Net and necessary regularization loss for them?&lt;/li&gt;
&lt;li&gt;Why mapping the first downsampling patch into the second downsampling patch is equivalent to mapping the original noisy image into the clean image?&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;cid-net&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cid-net&#34;&gt;#&lt;/a&gt;  &lt;code&gt;CID-Net&lt;/code&gt;&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;Maybe we can insert the HVI color space idea into ZS-N2N method?&lt;/li&gt;
&lt;/ul&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;保研是信息战。&lt;/p&gt;
&lt;p&gt;接触更多优质的人和优质的圈子，再加上自身努力，便可改变你的命运。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;本校学长浙大软院保研-朝花夕拾-次林梦叶-博客园-cnblogscom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#本校学长浙大软院保研-朝花夕拾-次林梦叶-博客园-cnblogscom&#34;&gt;#&lt;/a&gt; 本校学长（浙大软院）：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vY2lsaW5tZW5neWUvcC8xODQ0ODY2Mg==&#34;&gt;保研 朝花夕拾 - 次林梦叶 - 博客园 (cnblogs.com)&lt;/span&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;强 &lt;code&gt;Com&lt;/code&gt;  指的是研招办 &amp;gt; 老师，弱 &lt;code&gt;Com&lt;/code&gt;  相反。强 &lt;code&gt;Com&lt;/code&gt;  需要基础较为扎实，比如 &lt;code&gt;rk&lt;/code&gt;  和本科院校、英语四六级。弱 &lt;code&gt;Com&lt;/code&gt;  可以用简历陶瓷老师。&lt;/li&gt;
&lt;li&gt;准备机试需要刷算法题。&lt;/li&gt;
&lt;li&gt;四非不是 &lt;code&gt;rk1&lt;/code&gt;  都是一样。&lt;/li&gt;
&lt;li&gt;导师不回信才是正常情况，多陶瓷才是王道。&lt;/li&gt;
&lt;li&gt;面试普遍都要英语自我介绍 1 分钟。&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;华东师范记录我的2023届四非保研之rk边缘人无六级鸽浙大上岸华师软院学硕-starryfk-个人博客&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#华东师范记录我的2023届四非保研之rk边缘人无六级鸽浙大上岸华师软院学硕-starryfk-个人博客&#34;&gt;#&lt;/a&gt; （华东师范）&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc3RhcnJ5ZmsuY29tL2Vsc2UvcmVjb3JkLW15LTIwMjMtcG9zdGdyYWR1dGUtcmVjb21tZW5kYXRpb24uaHRtbCNkaXJlY3RvcnkwMTMyNTU0ODgzMDQyMzc3NzIyMw==&#34;&gt;记录我的 2023 届四非保研之 rk 边缘人无六级鸽浙大上岸华师软院学硕 - StarryFK 个人博客&lt;/span&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;学硕专硕区别：&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;../../assets/hdsd1.png&#34; alt=&#34;image&#34; /&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;不要去投歧视双非严重的学校。&lt;/li&gt;
&lt;li&gt;基本不要双非的学校：武汉大学、四川大学、上海交通大学、复旦大学、北京理工大学、同济大学、南京大学、华中科技大学、哈尔滨工业大学、中国科学技术大学（18 年有个老学长进去过，现在不太清楚）、中山大学、北京航空航天大学。&lt;/li&gt;
&lt;li&gt;有鸽双非历史的学校：天津大学、中南大学、东南大学、北京交通大学、湖南大学、西安交通大学、南开大学、西北工业大学（西工大 23 年有个 &lt;code&gt;rk&lt;/code&gt;  第一的学长还是进去过）。&lt;/li&gt;
&lt;li&gt;对双非四非友好的学校：吉林大学、东北大学、华东师范大学、大连理工大学、电子科技大学、重庆大学、山东大学、国防科技大学（有个 19 级学长进去过）、厦门大学、浙大软院、南大软院、中科大科学岛、苏研院、西安电子科技大学、北京邮电大学。其中有相当一部分是弱 &lt;code&gt;com&lt;/code&gt;  学校，推荐提前联系导师。&lt;/li&gt;
&lt;li&gt;海投，应投尽投，不漏一校。&lt;/li&gt;
&lt;li&gt;夏令营和预推免的资料应该提前准备好，按学校分类放到不同文件夹。&lt;/li&gt;
&lt;li&gt;信息渠道：学校官方网站、学校的研招公众号、保研机构公众号中的免费资讯，注意留意开营信息、绿群（保持交流也是督促自己、 保持热情的方式）。&lt;/li&gt;
&lt;li&gt;并不是没过夏令营的初审就不能继续投这个学校。&lt;/li&gt;
&lt;li&gt;浙大软院最近是 “点击就送”。&lt;/li&gt;
&lt;li&gt;浙大软院夏令营比较长，从 6 月 27 日到 7 月 15，认真准备每个环节是有很大机会拿到 &lt;code&gt;offer&lt;/code&gt;  的。&lt;/li&gt;
&lt;li&gt;夏令营 —— 凭借好看的简历进营完成项目，得到优营。预推免 —— 机试 + 面试，。一些学校有了夏令营优营后，预推免初审必过。&lt;/li&gt;
&lt;li&gt;有些学校老师在面试时可以看到机试成绩，会影响面试打分。当然有些学校的老师可能无法看到机试成绩。&lt;/li&gt;
&lt;li&gt;面试内容可能还会有人际关系、政治问题。&lt;/li&gt;
&lt;li&gt;不同组面试的侧重点不同，可能有的抓项目、有的抓专业课。&lt;/li&gt;
&lt;li&gt;如果实在很想去某个学校的话，可以联系导师取得优势，最好就是投特别想去的学校或者导师。&lt;/li&gt;
&lt;li&gt;预推免还是没办法的话，就真的无缘这个学校了。&lt;/li&gt;
&lt;li&gt;最好不要同时投一个学院的导师，特别是同一个实验室的导师，会显得非常没有诚意。&lt;/li&gt;
&lt;li&gt;联系导师一定要提前，首先可以通过邮件联系到老师，接着如果看到没有明确拒绝的话可以进一步邮件索要微信。加微信成功后，可以问面试的形式大概如何，可以围绕学术进行交流，必要时候可以保持和导师的交流。不要嫌导师话少，这并不代表导师对你的兴趣不大，只要导师还在和你交流，那么就还是有希望的，导师说不定可以在预推免的初审和后面的面试捞一把。&lt;/li&gt;
&lt;li&gt;预推免的面试部分，会比较刻意考验英语口语的能力，建议可以利用备考雅思口语的方式来锻炼自己的口语水平。&lt;/li&gt;
&lt;li&gt;国家推免系统在 9 月 28 日开放志愿的填报，在 9 月 23 日或 9 月 22 日左右可以进入系统确认保研资格和个人信息的填写和完善，如果发现自己没有显示具有保研资格，也不用着急，学校并不需要一开系统就上传推免名单的，耐心等待学校上传即可。&lt;/li&gt;
&lt;li&gt;在推免系统中，有些个人信息也是学校提交的，如果你发现信息不对，就要及时联系学校进行修改，所以也因此要提前进系统核对自己的信息，不要等到 928 再急急忙忙找学校修改。&lt;/li&gt;
&lt;li&gt;推免需要缴费。&lt;/li&gt;
&lt;li&gt;9 月 28 日凌晨开始填报志愿，然后招生学校在 9 月 28 日中午 12 点进入系统进行操作。&lt;/li&gt;
&lt;li&gt;在系统中填报志愿，有三个平行志愿可以填写，不需要一次全部填写三个。填报好一个志愿后，48 小时内就不能再更改了，除非是学校拒绝了你的志愿，你就可以修改该行的志愿到其他学校。&lt;/li&gt;
&lt;li&gt;对于没有 &lt;code&gt;offer&lt;/code&gt;  却在系统中填报了某校，一般来说都是采取默认拒绝的形式，也有不拒绝也不接受的，基本等于是浪费了一个志愿填报的位置了。&lt;/li&gt;
&lt;li&gt;如果学校接受了你的志愿，会发送复试通知，这时候需要点击确认来告知学校愿意参加复试。&lt;/li&gt;
&lt;li&gt;可以同时接受多个学校的复试考核。&lt;/li&gt;
&lt;li&gt;如果参加过夏令营或预推免，有了 &lt;code&gt;offer&lt;/code&gt; ，复试可以直接通过，学校会发送复试通过的通知，并且发送待录取通知。&lt;/li&gt;
&lt;li&gt;复试通知和预推免通知都有一定的时间限制，超过时间不接受，学校就会撤回通知。&lt;/li&gt;
&lt;li&gt;一旦接受了待录取通知，那么就结束了推免，无法再撤回，也无法再接受其他学校的复试和录取通知。&lt;/li&gt;
&lt;li&gt;要留意学校要求的最迟确认复试通知和最迟确认录取通知。&lt;/li&gt;
&lt;li&gt;（感觉可以参考一下这个贴的佬学习英语的方法）&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;北京大学深圳研究院2022年计算机保研夏令营预推免经验帖2023届-知乎-zhihucom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#北京大学深圳研究院2022年计算机保研夏令营预推免经验帖2023届-知乎-zhihucom&#34;&gt;#&lt;/a&gt; （北京大学深圳研究院）&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aHVhbmxhbi56aGlodS5jb20vcC81NDg2NjA5NzY=&#34;&gt;2022 年计算机保研夏令营 &amp;amp; 预推免经验帖（2023 届） - 知乎 (zhihu.com)&lt;/span&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;强 &lt;code&gt;Com&lt;/code&gt;  的夏令营较侧重 &lt;code&gt;rk&lt;/code&gt; ，参加弱 &lt;code&gt;Com&lt;/code&gt;  的夏令营需要提前套磁老师，然后老师往学校推荐自己入营。&lt;/li&gt;
&lt;li&gt;大多数夏令营通过机试 + 面试来确定优营，机试推荐复习王道的机试指南。&lt;/li&gt;
&lt;li&gt;夏令营也可能考察专业课和数学，所以也要做相关的 zhun&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;计算所关于保研的abc1一些常识与概念-sumskys-blog&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算所关于保研的abc1一些常识与概念-sumskys-blog&#34;&gt;#&lt;/a&gt; （计算所）&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zdW1za3kudG9wLzIwMjEvMTAvMTMvYmFveWFuLXNlcmllcy0xLw==&#34;&gt;关于保研的 ABC（1）一些常识与概念 | Sumsky&#39;s Blog&lt;/span&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;可以关注相关学院的研招群。&lt;/li&gt;
&lt;li&gt;申请直博项目或者对于导师水平和方向比较看重的话，请务必抓住夏令营难这一难得机会，很多时候预推免即便上岸，也只能挑夏令营被选过一轮之后剩下的老师了。&lt;/li&gt;
&lt;li&gt;不确定是否能够拿到推免资格依然可以参加夏令营和预推免，只要用自己的成绩让招生单位相信你预期可以获得推免资格即可。&lt;/li&gt;
&lt;li&gt;预推免和夏令营都可以报多所学校，只是要注意是否时间会发生冲突。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;Offer&lt;/code&gt;  本质上只是一种非正式的 “契约”，因此无论是否签承诺书，这类承诺都不具备法律效力。&lt;/li&gt;
&lt;li&gt;尽管学校已经给了 &lt;code&gt;Offer&lt;/code&gt; ，确实有学校会鸽学生的情况。&lt;/li&gt;
&lt;li&gt;不过学校鸽学生这种现象对于学校的声誉是一个重大的打击，因此绝大多数学校一般都不会做这种事情。&lt;/li&gt;
&lt;li&gt;导师 / 课题组鸽学生的现象其实比学校鸽学生的现象更为普遍， 比如说在夏令营联系好了的实验室，在九推时突然以 “今年名额减少了” 的理由不再承诺一定会录取。&lt;/li&gt;
&lt;li&gt;推免系统开放前，尽量只保留一个 &lt;code&gt;offer&lt;/code&gt; ，能早放弃尽量早放弃（存疑）&lt;/li&gt;
&lt;li&gt;毕业要求中，一般学硕略高于专硕，有些学校对于两种类型的硕士同等对待，但是毕业出去学硕的待遇一般比专硕好。&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;西安电子科技大学杭州研究院2023年24届劣势四非躺平摆烂保研反面经验贴厦大-西北工业-西电杭-知乎-zhihucom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#西安电子科技大学杭州研究院2023年24届劣势四非躺平摆烂保研反面经验贴厦大-西北工业-西电杭-知乎-zhihucom&#34;&gt;#&lt;/a&gt; （西安电子科技大学杭州研究院）&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aHVhbmxhbi56aGlodS5jb20vcC82NTkxNTQxNDQ=&#34;&gt;2023 年 24 届劣势四非躺平摆烂保研反面经验贴（厦大 西北工业 西电杭） - 知乎 (zhihu.com)&lt;/span&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;本科院校 &amp;gt;&amp;gt;&amp;gt; 专业排名 &amp;gt; 科研 &amp;gt; 竞赛 &amp;gt; 其他。前两者决定能否通过研招办的审核，后面几项决定能否拿到 &lt;code&gt;offer&lt;/code&gt; 。&lt;/li&gt;
&lt;li&gt;科研实习看的是态度而非仅仅知识水平。&lt;/li&gt;
&lt;li&gt;在拿到真正的 &lt;code&gt;offer&lt;/code&gt;  之前不要停止联系其他老师。&lt;/li&gt;
&lt;li&gt;不建议手握多个 &lt;code&gt;offer&lt;/code&gt; ，只建议手里拿 &lt;code&gt;1~2&lt;/code&gt;  个 &lt;code&gt;offer&lt;/code&gt;  就够了。拿到更好的学校后，及时放弃当前的 &lt;code&gt;offer&lt;/code&gt; ，别报名去不想去的学校，占用别人的机会。&lt;/li&gt;
&lt;li&gt;四非双非友好学校：厦大、浙大海洋、浙大海宁、国防科大、西电杭、华东师范软院、吉大、东北大学、华东师范、大连理工、电子科大、重大、山大、南大软院、中科大科学岛、苏研院、北邮、浙软。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://pic1.zhimg.com/v2-c783a05c4ce42cfcb7158be2a8375120_1440w.jpg&#34; alt=&#34;img&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;成电保研经验分享双非计算机上岸成电-码途拾遗-fangkaipengcom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#成电保研经验分享双非计算机上岸成电-码途拾遗-fangkaipengcom&#34;&gt;#&lt;/a&gt; （成电）&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9mYW5na2FpcGVuZy5jb20vP3A9MjEwMw==&#34;&gt;保研经验分享（双非计算机上岸成电） – 码途拾遗 (fangkaipeng.com)&lt;/span&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;有些弱 &lt;code&gt;com&lt;/code&gt;  甚至不看机试只看面试，甚至没有夏令营，只在预推免发 &lt;code&gt;offer&lt;/code&gt; ，比如这个成电。&lt;/li&gt;
&lt;li&gt;夏令营也有许多不同类型，有些夏令营是宣传性质，不发优营和 &lt;code&gt;offer&lt;/code&gt; 。一般夏令营在 5-6 月份申请，在 6-8 月份参营。一般的夏令营都有考核，常见的流程是机试、面试等、评选优营。而且，根据学校不同，优营的作用不同，有的可以直接作为 &lt;code&gt;offer&lt;/code&gt; ，有的没有夏令营 &lt;code&gt;offer&lt;/code&gt;  则不允许参加预推免。&lt;/li&gt;
&lt;li&gt;预推免一般在 8 月末到 9 月 28 日之间。&lt;/li&gt;
&lt;li&gt;大三寒假后就可以开始准备复习专业课了，4 月份之前可以准备个人文书材料，可以对个人的证明材料按学校分类归档。一般在 4-5 月份就可以对导师进行陶瓷。&lt;/li&gt;
&lt;li&gt;可以按照 &lt;code&gt;excel&lt;/code&gt;  表收集和准备夏令营和预推免的材料，可以在大三下开学后就开始进行。&lt;/li&gt;
&lt;li&gt;关于导师推荐信，手写大于打印，这种东西只是一个形式，有了就行，具体细节不会太重要。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;Scanner Mini&lt;/code&gt;  是 &lt;code&gt;IOS&lt;/code&gt;  的一个扫描工具，可用于整理材料时，将纸质转换为电子。&lt;/li&gt;
&lt;li&gt;一般而言，专业课优先级为：数据结构 &amp;gt; 操作系统 &amp;gt; 计算机网络 = 计算机组成原理。对于数学课，线性代数 &amp;gt; 概率论 &amp;gt; 高等数学。&lt;/li&gt;
&lt;li&gt;下面放上计算机专业国内高校天梯图（爱来自绿群）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;../../assets/%E5%AD%A6%E6%A0%A1%E6%8E%92%E5%90%8D.jpg&#34; alt=&#34;image&#34; /&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;非热门研究组，竞争压力：直博 &amp;lt; 专硕 &amp;lt; 学硕。&lt;/li&gt;
&lt;li&gt;选组和导师可以参考：组实力（毕业去向、每年论文数量等）、组氛围、导师水平（头衔、 &lt;code&gt;google&lt;/code&gt;  引用、每年论文数等）、导师性格（是否 &lt;code&gt;push&lt;/code&gt; 、是否 &lt;code&gt;pua&lt;/code&gt; 、是否允许实习、他人口碑等）&lt;/li&gt;
&lt;li&gt;如果导师的论文大部分一作都不是学生而是他（她）自己，就需要慎重考虑。&lt;/li&gt;
&lt;li&gt;可以从 &#39;&#39; 导师评价 &lt;code&gt;.excel&lt;/code&gt; &#39;&#39; 文件中了解导师口碑。&lt;/li&gt;
&lt;li&gt;学校官网可以看到导师的教育背景、主要成果和头衔。&lt;/li&gt;
&lt;li&gt;陶瓷老师也可以分为稳和冲。一般大牛导师用来冲，最好提前去陶瓷（4-5 月），也不用太多准备，直接上，能收就血赚，不能收还有稳的老师去陶。稳的导师最好也是在夏令营前 1 个月左右陶瓷（其实最好就是在 5 月份左右）。&lt;/li&gt;
&lt;li&gt;用于陶瓷的邮箱建议为：教育邮箱 &amp;gt; &lt;code&gt;gmail&lt;/code&gt;  &amp;gt; 网易邮箱。&lt;/li&gt;
&lt;li&gt;发邮件的时间建议为：早上 &lt;code&gt;7：00&lt;/code&gt; ，中午 &lt;code&gt;13：00&lt;/code&gt; 。&lt;/li&gt;
&lt;li&gt;可能一个组有多个导师，这时候就要注意同一个组建议同时只陶瓷一个导师，过段时间（一个星期左右）再陶瓷同组的下一个导师。&lt;/li&gt;
&lt;li&gt;陶瓷前可以反复进行自我介绍的练习和项目介绍，这样可以保证嘴巴和脑子处于一个活跃的状态。&lt;/li&gt;
&lt;li&gt;陶瓷过程其实没有那么正式，实际上就是在和导师有说有笑，比较轻松。&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;读博你真的想好了吗-知乎-zhihucom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#读博你真的想好了吗-知乎-zhihucom&#34;&gt;#&lt;/a&gt; &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aHVhbmxhbi56aGlodS5jb20vcC8zNzI4ODQyNTM=&#34;&gt;读博，你真的想好了吗？ - 知乎 (zhihu.com)&lt;/span&gt;&lt;/h1&gt;
&lt;h1 id=&#34;港中深直博2022计算机保研申请记录港三清北华五人计算所-搜索结果-知乎-zhihucom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#港中深直博2022计算机保研申请记录港三清北华五人计算所-搜索结果-知乎-zhihucom&#34;&gt;#&lt;/a&gt; （港中深直博）&lt;span class=&#34;exturl&#34; data-url=&#34;&#34;&gt;2022 计算机保研 / 申请记录（港三 / 清北 / 华五人 / 计算所） - 搜索结果 - 知乎 (zhihu.com)&lt;/span&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;清深现在入营了的都是联系过的。&lt;/li&gt;
&lt;li&gt;一般学校层次越高，对机试 &lt;code&gt;or&lt;/code&gt;  数据结构与算法的要求越高。&lt;/li&gt;
&lt;li&gt;南大的夏令营是海营，机试比较杂。&lt;/li&gt;
&lt;li&gt;计算所的导师联系导师很重要，就算没报名夏令营都能直接发 &lt;code&gt;offer&lt;/code&gt; 。&lt;/li&gt;
&lt;li&gt;真诚和老师沟通很重要，即使在等待某个学校的答复，也要坦诚和老师说，老师会理解。所以，就算到时候去了其他的学校，老师也不会很怪罪，不少老师也会鼓励学生冲击更好的去处，并愿意保留一定的时间。&lt;/li&gt;
&lt;li&gt;中国人大信息学院是鸽院，面试需要签保密协议。&lt;/li&gt;
&lt;li&gt;不要完全相信老师的口头话语，公示的名单才是硬道理！&lt;/li&gt;
&lt;li&gt;预推免 &lt;code&gt;wl&lt;/code&gt;  就算成功！临近开系统，真的很多学校 wl 候补到最后面，在候补名单就有希望。&lt;/li&gt;
&lt;li&gt;敢于联系，一切皆有可能。&lt;/li&gt;
&lt;li&gt;提前规划复习！填报系统挺费时间的，要留出足够多的时间准备起码考和各种填报、机试、面试！&lt;/li&gt;
&lt;/ul&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;本博文涉及《数据库系统概论》第 6 版的主要理论知识，包含了前 7 章的理论知识。以题单的形式记录核心知识以应对期末考试。如有错误，欢迎纠正。&lt;br /&gt;
上一期的内容在《数据库系统概论（二）》中，包含了绪论，关系模型，数据库安全与触发器的内容。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;关系代数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关系代数&#34;&gt;#&lt;/a&gt; 关系代数&lt;/h1&gt;
&lt;ol&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;关系代数的运算对象是关系，运算结果不是关系。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;关系代数的运算结果还是关系。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;关系代数分为传统的集合运算和专门的关系运算，则专门的关系运算有哪些？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;选择。&lt;/li&gt;
&lt;li&gt;笛卡尔积。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;连接。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;除。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;投影。&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;传统的集合运算有并，差，交，笛卡尔积。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;关系的差运算，对于两个关系 R 和 S，R-S 和 S-R 一定是等价的。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;关系的差运算有顺序，R-S 与 S-R 一般不等价。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;关系代数中，表示不等于的运算符是！=。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;表示不等于的运算符只能是 &amp;lt;&amp;gt;。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;用关系代数查询信息安全专业的全体学生。&lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;msup&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mtext&gt;信息安&lt;/mtext&gt;&lt;msup&gt;&lt;mtext&gt;全&lt;/mtext&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sigma_{Smajor=&amp;#x27;信息安全&amp;#x27;}(Student)
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.036108em;vertical-align:-0.286108em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;σ&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.328331em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;&lt;span class=&#34;mrel mtight&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.6828285714285715em;&#34;&gt;&lt;span style=&#34;top:-2.786em;margin-right:0.07142857142857144em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.5em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size3 size1 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback mtight&#34;&gt;信&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback mtight&#34;&gt;息&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback mtight&#34;&gt;安&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord cjk_fallback mtight&#34;&gt;全&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.6828285714285715em;&#34;&gt;&lt;span style=&#34;top:-2.786em;margin-right:0.07142857142857144em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.5em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size3 size1 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.286108em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;常见的在选择运算的条件表达式的运算符有 &amp;gt;(大于),&amp;gt;=(大于等于),&amp;lt;(小于),&amp;lt;=(小于等于),=(等于),&amp;lt;&amp;gt;(不等于),&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;¬&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lnot&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;¬&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; (非),&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∧&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\land&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∧&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; (与),&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∨&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lor&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∨&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; (或)。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;查询 2001 年后（包含 2001 年）出生的学生。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mo&gt;&amp;gt;&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;2001&lt;/mn&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sigma_{Sbirthdate&amp;gt;=2001-1-1}(Student)
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;σ&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.3361079999999999em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mbin mtight&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mbin mtight&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.208331em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;查询学生的学号和主修专业。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;π&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\pi_{Sno,Smajor}(Student)
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.036108em;vertical-align:-0.286108em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;π&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.328331em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mpunct mtight&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.286108em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;检索选修课程号为 C1 的学生学号与成绩。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/p&gt;
