&lt;li class=&#34;quiz fill&#34;&gt;检索同时选修了至少两门课程的学生学号与姓名。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; Sno&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Sname &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; Student&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; Sno &lt;span class=&#34;token operator&#34;&gt;IN&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; Sno &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; SC &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; 	&lt;span class=&#34;token keyword&#34;&gt;GROUP&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;BY&lt;/span&gt; SNO&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   	&lt;span class=&#34;token keyword&#34;&gt;HAVING&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;COUNT&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;28&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;检索至少选修 LIU 老师所授课程中一门课程的女学生姓名、课程名及成绩。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; a&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sname&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; c&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cname&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Grade &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; Student a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; SC b&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Course c&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; a&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sno&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;b&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sno &lt;span class=&#34;token operator&#34;&gt;AND&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cno&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;c&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cno &lt;span class=&#34;token operator&#34;&gt;AND&lt;/span&gt; a&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Ssex&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;女&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;AND&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Teacher &lt;span class=&#34;token operator&#34;&gt;LIKE&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;LIU%&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;29&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;检索 ZHANG 老师所授课程的每门课程的平均成绩。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;AVG&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;SC&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Grade&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; SC&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Course&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; SC&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cno&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;Course&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cno &lt;span class=&#34;token operator&#34;&gt;AND&lt;/span&gt; Course&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Teacher &lt;span class=&#34;token operator&#34;&gt;LIKE&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;ZHANG%&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;GROUP&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;BY&lt;/span&gt; SC&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cno&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;30&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;检索所有女学生的学号和姓名，并按学号逆序排序。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; Sno&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Sname &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; Student&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; Ssex&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;女&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;ORDER&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;BY&lt;/span&gt; Sno &lt;span class=&#34;token keyword&#34;&gt;DESC&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;31&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;检索同时选修了至少三门课程的学生学号与姓名。 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; Student&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sno&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Student&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sname &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; Student&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; SC&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; Student&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sno&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;SC&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sno&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;GROUP&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;BY&lt;/span&gt; Student&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sno&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;HAVING&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;COUNT&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;SC&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cno&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;数据库设计&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据库设计&#34;&gt;#&lt;/a&gt; 数据库设计&lt;/h1&gt;
&lt;ol start=&#34;92&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据库设计的基本步骤有 &lt;span class=&#34;gap&#34;&gt;需求分析阶段&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;概念结构设计阶段&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;逻辑结构设计阶段&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;物理结构设计阶段&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;数据库实施阶段&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;数据库运行和维护阶段&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据字典是进行详细的 &lt;span class=&#34;gap&#34;&gt;数据收集&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;数据分析&lt;/span&gt; 之后所获得的主要成果。它是关于数据库中对数据的 &lt;span class=&#34;gap&#34;&gt;描述&lt;/span&gt;，即元数据，而不是数据本身。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;数据字典在需求分析阶段被建立，在数据库设计过程中不断修改、充实和完善。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;数据字典通常包括哪些部分？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;数据项。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据结构。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据流。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据存储。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;处理过程。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;数据项是数据的最小组成单位，若干个数据项能组成一个数据结构。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;本博文涉及《数据库系统概论》第 6 版的主要理论知识，包含了前 7 章的理论知识。以题单的形式记录核心知识以应对期末考试。如有错误，欢迎纠正。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;绪论&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#绪论&#34;&gt;#&lt;/a&gt; 绪论&lt;/h1&gt;
&lt;h2 id=&#34;数据库系统概述&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据库系统概述&#34;&gt;#&lt;/a&gt; 数据库系统概述&lt;/h2&gt;
&lt;ol&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;描述事物的 &lt;span class=&#34;gap&#34;&gt;符号记录&lt;/span&gt; 称为数据。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据的 &lt;span class=&#34;gap&#34;&gt;含义&lt;/span&gt; 称为数据的语义，数据与其语义是不可分的。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据库是长期存储在计算机内 &lt;span class=&#34;gap&#34;&gt;有组织、可共享&lt;/span&gt; 的大量数据的集合。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据库中的数据具有较小的 &lt;span class=&#34;gap&#34;&gt;数据冗余&lt;/span&gt;、较高的 &lt;span class=&#34;gap&#34;&gt;数据独立性&lt;/span&gt;和 &lt;span class=&#34;gap&#34;&gt;可扩展性&lt;/span&gt;，并可为各种用户 &lt;span class=&#34;gap&#34;&gt;共享&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;数据库管理系统与操作系统都是软件，但数据库管理系统是操作系统和用户的接口，操作系统是软件和硬件的接口。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;数据库管理系统的英文缩写是 DBMS。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据库管理系统是位于 &lt;span class=&#34;gap&#34;&gt;用户&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;操作系统&lt;/span&gt; 之间的数据管理软件。它和操作系统一样是计算机的基础软件。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;数据库管理系统的主要功能有&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;数据定义功能。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据组织、存储和管理功能。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据操纵功能。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据库的事务管理和运行管理功能。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据库的建立和维护功能。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;数据定义语言的英文缩写是 DML，数据操纵语言的英文缩写是 DDL。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;定义是 DDL（Data Definition Language）。操纵是 DML（Data Manipulation Language）。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;数据库系统的英文缩写是 DBS。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据库系统是指引入 &lt;span class=&#34;gap&#34;&gt;数据库&lt;/span&gt; 的计算机系统，一般是指由 &lt;span class=&#34;gap&#34;&gt;数据库&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;数据库管理系统&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;应用系统&lt;/span&gt;和&lt;span class=&#34;gap&#34;&gt;数据库管理员&lt;/span&gt;组成的存储、管理、处理和维护数据的系统。	&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;&lt;span class=&#34;gap&#34;&gt;数据管理&lt;/span&gt; 是指对数据进行分类、组织、编码、存储、检索和维护，它是数据处理的中心问题。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据库管理技术经历了 &lt;span class=&#34;gap&#34;&gt;人工管理&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;文件系统&lt;/span&gt;和&lt;span class=&#34;gap&#34;&gt;数据库系统&lt;/span&gt; 三个阶段。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;人工管理阶段的数据有哪些特点？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;数据不保存。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;应用程序管理数据。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据不共享。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据不具有独立性。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;文件系统阶段的数据有哪些特点？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;数据可以长期保存。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据由专门的软件进行管理。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据共享性弱，冗余度高。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据独立性弱。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;数据库系统阶段的数据有哪些特点？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;整体数据结构化。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据的共享性强、冗余度低且易于扩充。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据的独立性强。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据由数据库管理系统统一管理和控制。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;数据库管理系统除了提供第八题所述的主要功能外，还需要提供哪些功能？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;数据的安全性保护。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据的完整性检查。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据的并发性控制。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据库的恢复。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;数据模型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据模型&#34;&gt;#&lt;/a&gt; 数据模型&lt;/h2&gt;
&lt;ol start=&#34;18&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据模型也是一种模型，它是对现实世界 &lt;span class=&#34;gap&#34;&gt;数据特征&lt;/span&gt; 的抽象。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz&#34;&gt;
&lt;p&gt;什么是数据库系统的核心和基础？ &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li&gt;概念模型。&lt;/li&gt;
&lt;li&gt;E-R 图。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据模型。&lt;/li&gt;
&lt;li&gt;数据结构。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;把现实世界中的具体事物抽象、组织为某一数据库管理系统所支持的数据模型，这个过程称为 &lt;span class=&#34;gap&#34;&gt;数据建模&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据建模主要有两步，分别为 &lt;span class=&#34;gap&#34;&gt;建立概念模型&lt;/span&gt;和 &lt;span class=&#34;gap&#34;&gt;将概念模型转换为数据模型&lt;/span&gt;。	&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;概念模型是按 &lt;span class=&#34;gap&#34;&gt;用户&lt;/span&gt; 的观点来对数据建模，主要用于 &lt;span class=&#34;gap&#34;&gt;数据库设计&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据模型是按 &lt;span class=&#34;gap&#34;&gt;计算机系统&lt;/span&gt; 的观点对数据建模，是数据库管理系统支持的，用于 &lt;span class=&#34;gap&#34;&gt;数据库管理系统&lt;/span&gt; 的实现。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;客观存在并可相互区别的事物称为 &lt;span class=&#34;gap&#34;&gt;实体&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;实体所具有的某一特性称为 &lt;span class=&#34;gap&#34;&gt;属性&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;唯一标识实体的属性集称为 &lt;span class=&#34;gap&#34;&gt;码&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;同一类型实体的集合称为 &lt;span class=&#34;gap&#34;&gt;实体集&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;实体内部的联系通常是指组成实体的 &lt;span class=&#34;gap&#34;&gt;各属性&lt;/span&gt; 之间的联系，实体之间的联系通常是指 &lt;span class=&#34;gap&#34;&gt;不同实体集&lt;/span&gt; 之间的联系。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;实体之间的联系有一对一、一对多、多对多、多对一等多种类型。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;实体之间的联系没有多对一的类型。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;通常用 &lt;span class=&#34;gap&#34;&gt;E-R 图&lt;/span&gt; 来描述现实世界的概念模型。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;这种方式构建了一个 E-R 模型。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;实体用 &lt;span class=&#34;gap&#34;&gt;矩形&lt;/span&gt; 来表示。属性用 &lt;span class=&#34;gap&#34;&gt;椭圆&lt;/span&gt; 来表示。联系用 &lt;span class=&#34;gap&#34;&gt;菱形&lt;/span&gt; 来表示。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;所有表都是实体。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;并非所有的表都是实体，表是实体集的呈现方式与存储方式，表既可以是实体也可以是联系。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据模型的三要素是 &lt;span class=&#34;gap&#34;&gt;数据结构&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;数据操纵&lt;/span&gt;和&lt;span class=&#34;gap&#34;&gt;完整性约束&lt;/span&gt;。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;数据模型的三要素实际上就是数据模型的组成部分。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据结构描述数据库的 &lt;span class=&#34;gap&#34;&gt;组成对象&lt;/span&gt; 以及 &lt;span class=&#34;gap&#34;&gt;对象之间&lt;/span&gt; 之间的联系。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据操纵是指对数据库中各种对象（型）和实例（值）允许执行的 &lt;span class=&#34;gap&#34;&gt;操作&lt;/span&gt; 的集合。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;数据操纵包括数据操作以及有关的操作规则。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;完整性规则是给定的数据模型中的数据及其联系所具有的 &lt;span class=&#34;gap&#34;&gt;制约和依存规则&lt;/span&gt;，用以限定符合数据模型的数据库状态以及状态的变化，以保证数据的正确、有效和相容。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系模型由一组关系组成，每个关系的数据结构是一张 &lt;span class=&#34;gap&#34;&gt;规范化的二维表&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系表中的一行即为一个 &lt;span class=&#34;gap&#34;&gt;元组&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;元组又称为记录。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系表中的一列即为一个 &lt;span class=&#34;gap&#34;&gt;属性&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;每列的名称即为属性名。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;&lt;span class=&#34;gap&#34;&gt;码&lt;/span&gt; 是关系表中的属性集，能唯一标识一条记录。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;&lt;span class=&#34;gap&#34;&gt;域&lt;/span&gt; 表示某一属性的取值范围，通常是一组具有相同数据类型的值的集合。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;&lt;span class=&#34;gap&#34;&gt;分量&lt;/span&gt; 是元组中一个属性值。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;特指在元组内。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系模式要求关系必须是 &lt;span class=&#34;gap&#34;&gt;规范化&lt;/span&gt; 的。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;规范条件中最基本的一条就是：关系的每个分量必须是一个不可分的数据项，即行不可分，不允许表中还有表。这就是 1NF。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;数据操纵是 &lt;span class=&#34;gap&#34;&gt;集合&lt;/span&gt; 操作，操作对象和操作结果都是 &lt;span class=&#34;gap&#34;&gt;关系&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;关系模型有哪些优点？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;关系模型建立在严格的数学概念基础上。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;关系模型的概念单一。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;关系模型的存取路径对用户隐蔽。&lt;/li&gt;
&lt;li&gt;降低了开发关系数据库管理系统的难度。&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关系模型的缺点是：查询效率较低；增加了开发关系数据库管理系统的难度。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;数据库系统的三级模式结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据库系统的三级模式结构&#34;&gt;#&lt;/a&gt; 数据库系统的三级模式结构&lt;/h2&gt;
&lt;ol start=&#34;46&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;型是指对某一类数据的结构和属性的说明，值是型的一个具体赋值。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;模式是数据库中全体数据的 &lt;span class=&#34;gap&#34;&gt;逻辑结构&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;特征&lt;/span&gt; 的描述。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;模式的一个具体值称为模式的一个 &lt;span class=&#34;gap&#34;&gt;实例&lt;/span&gt;。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;同一个模式可以有很多实例。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;模式反映的是数据的结构及其联系，而实例反映的是数据库某一时刻的状态。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;模式是所有用户的 &lt;span class=&#34;gap&#34;&gt;公共数据&lt;/span&gt; 视图。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;三级模式结构是指数据库系统是由 &lt;span class=&#34;gap&#34;&gt;模式&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;外模式&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;内模式&lt;/span&gt;三级构成。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;一个数据库对应一个模式。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;外模式是数据库用户能够看见和使用的 &lt;span class=&#34;gap&#34;&gt;局部&lt;/span&gt; 数据的 &lt;span class=&#34;gap&#34;&gt;逻辑结构&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;特征&lt;/span&gt; 的描述。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;外模式是数据库用户的数据视图，是与某一应用有关的数据的逻辑表示。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;一个数据库只能有一个外模式。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;一个数据库可以有多个外模式。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;同一外模式也可以为某一用户的多个应用系统所使用，但一个应用程序只能使用一个外模式。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;内模式是对数据 &lt;span class=&#34;gap&#34;&gt;物理结构&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;存储方式&lt;/span&gt; 的描述，是数据在数据库内部的组织方式。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;一个数据库只能有一个内模式。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;两级映像实现了模式、内模式和外模式这三个抽象层次的联系和转换。两级映像包括 &lt;span class=&#34;gap&#34;&gt;外模式 // 模式映像&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;模式 // 内模式映像&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;两级映像的存在，保证了数据库系统中的数据能够具有较强的逻辑独立性和物理独立性。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;当模式改变时，数据库管理员对外模式 // 模式映像进行改变，可以使得 &lt;span class=&#34;gap&#34;&gt;外模式&lt;/span&gt; 保持不变，因而应用程序不必修改，保证了数据与程序的逻辑独立性，简称 &lt;span class=&#34;gap&#34;&gt;数据的逻辑独立性&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;一个数据库不只有一个外模式 // 模式映像。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;当数据库的存储结构改变时，数据库管理员对模式 // 内模式映像进行改变，可以使 &lt;span class=&#34;gap&#34;&gt;模式&lt;/span&gt; 保持不变，因而应用程序也不必改变，保证了数据与程序的物理独立性，简称 &lt;span class=&#34;gap&#34;&gt;数据的物理独立性&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;数据库系统的组成包括硬件平台、软件平台、人员，其中人员包括&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;数据库管理员。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;系统分析员。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;数据库设计员。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;应用程序员。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;最终用户。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;关系模型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关系模型&#34;&gt;#&lt;/a&gt; 关系模型&lt;/h1&gt;
&lt;h2 id=&#34;关系模型的数据结构和形式化定义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关系模型的数据结构和形式化定义&#34;&gt;#&lt;/a&gt; 关系模型的数据结构和形式化定义&lt;/h2&gt;
&lt;ol start=&#34;63&#34;&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;笛卡尔积不允许域相同。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;笛卡尔积是域上的一种集合运算。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;一个域允许的不同取值个数称为这个域的 &lt;span class=&#34;gap&#34;&gt;基数&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;笛卡尔积的基数由组成它的所有域的基数累乘而来。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;笛卡尔积没有实际语义，只有它的某个真子集才有实际含义。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;某组域上的笛卡尔积的子集称为这组域上的 &lt;span class=&#34;gap&#34;&gt;关系&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;笛卡尔积的域的个数称为在这组域上关系的目（或度）。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;目常被认为是属性列的个数。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;关系有哪三种类型？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;基本关系（通常又称为基本表）。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;查询结果。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;视图。&lt;/li&gt;
&lt;li&gt;触发器。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;基本关系有哪 6 条性质？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;列是同质的，每个列中的分量来自同一个域。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;不同的列可出自同一个域。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;列的顺序无所谓。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;行的顺序无所谓。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;每个分量必须是不可分的数据项。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;任意两个元组的码不能取相同的值。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在关系模型中，关系是元组的集合，关系是值；关系模型是对关系的描述，关系模式是型。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系模式可以形式化地表示为：R (U,D,DOM,F)。其中，R 是关系名，U 是组成该关系的 &lt;span class=&#34;gap&#34;&gt;属性的属性名&lt;/span&gt; 的集合，D 是 U 中属性所来自的 &lt;span class=&#34;gap&#34;&gt;域&lt;/span&gt;，DOM 为属性向域的 &lt;span class=&#34;gap&#34;&gt;映像集合&lt;/span&gt;，F 是属性间 &lt;span class=&#34;gap&#34;&gt;数据依赖关系&lt;/span&gt; 的集合。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;关系模式可以简写为：R (U) 或 R (A_1,A_2,...,A_n)，A_i 是属性名。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;若关系模式中某一个属性或一组属性的值能唯一地标识一个元组，而它的真子集不能唯一地标识一个元组，则称该属性或属性组为 &lt;span class=&#34;gap&#34;&gt;候选码&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;若一个关系有多个候选码，则选定其中一个为主码。&lt;br /&gt;
候选码是能唯一标识一条记录的最小属性集。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;候选码的诸属性称为 &lt;span class=&#34;gap&#34;&gt;主属性&lt;/span&gt;。不包含在&lt;strong&gt;任何&lt;/strong&gt;候选码中的属性称为 &lt;span class=&#34;gap&#34;&gt;非主属性&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系模式的所有属性是这个关系模式的候选码，称为 &lt;span class=&#34;gap&#34;&gt;全码&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;关系模式是静态的、稳定的，而关系是动态的、随时间不断变化的。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系数据库模式是关系数据库中 &lt;span class=&#34;gap&#34;&gt;所有关系模式&lt;/span&gt; 的集合，是对关系数据库的描述。关系数据库是这些关系模式在某一时刻对应的 &lt;span class=&#34;gap&#34;&gt;关系&lt;/span&gt; 的集合。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;关系操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关系操作&#34;&gt;#&lt;/a&gt; 关系操作&lt;/h2&gt;
&lt;ol start=&#34;79&#34;&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;哪些是 5 个基本关系操作？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;笛卡尔积。&lt;/li&gt;
&lt;li&gt;交。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;并。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;投影。&lt;/li&gt;
&lt;li&gt;连接。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;F. 选择。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;G. 差。&lt;/li&gt;
&lt;li&gt;H. 补。&lt;/li&gt;
&lt;li&gt;I. 除。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;一个关系数据语言能够表示关系代数可以表示的查询，则称其具有完备的表达能力，简称 &lt;span class=&#34;gap&#34;&gt;关系完备性&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;关系数据语言是用于操纵关系数据的语言。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;关系数据语言类型有哪些？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;关系代数。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;SQL 语言。&lt;/li&gt;
&lt;li&gt;C 语言。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;关系演算。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;关系的完整性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关系的完整性&#34;&gt;#&lt;/a&gt; 关系的完整性&lt;/h2&gt;
&lt;ol start=&#34;82&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;关系模型中有三类完整性约束：&lt;span class=&#34;gap&#34;&gt;实体完整性&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;参照完整性&lt;/span&gt;和&lt;span class=&#34;gap&#34;&gt;用户定义的完整性&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;关系的两个不变性是指关系模型必须满足实体完整性和用户定义的完整性。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;关系模式必须满足的两个完整性是实体完整性和参照完整性。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;实体完整性约束的关键是 “主码非空且唯一”。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;参照完整性约束的关键是 “外码为空或与被参照表主码相等”。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;参照完整性约束中，外码在参照表中，外码与被参照表中的主码值相等。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;参照完整性约束中，参照表和被参照表可以是同一张表。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;数据库安全与触发器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据库安全与触发器&#34;&gt;#&lt;/a&gt; 数据库安全与触发器&lt;/h1&gt;
&lt;h2 id=&#34;存取控制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存取控制&#34;&gt;#&lt;/a&gt; 存取控制&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;存取控制机制确保了只授权给有资格的用户访问数据库的权限，同时令所有未被授权的人员无法接近数据。存取控制机制主要包括定义用户权限和合法权限检查两部分。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;88&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;存取控制方法分为 &lt;span class=&#34;gap&#34;&gt;自主存取控制方法&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;强制存取控制方法&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;自主存取控制方法中，同一用户对于不同的数据库对象有不同的存取权限。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;自主存取控制方法中，不同用户对于同一数据库对象的权限相同。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;不同用户对同一数据库对象的存取权限也不同。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;自主存取控制方法中，用户可以将拥有的存取权限转授给其他用户。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;强制存取控制方法中，每一个数据库对象都被标以一定的密级。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;强制存取控制方法中，每一个用户会被授予某一个级别的许可证。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;强制存取控制方法中，对于任意一个数据库对象，任何用户都能存取。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;在强制存取控制方法中，只有具有合法许可证的用户才能存取当前的数据库对象。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;触发器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#触发器&#34;&gt;#&lt;/a&gt; 触发器&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;触发器又叫做事件 - 条件 - 动作规则。当特定的系统事件（如对一个表的更新操作，事务的结束等）发生时，对规则的条件进行检查，如果条件成立则执行规则中的动作，否则不执行该动作。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;95&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;触发器是用户定义在 &lt;span class=&#34;gap&#34;&gt;关系表&lt;/span&gt; 上的一类由 &lt;span class=&#34;gap&#34;&gt;事件&lt;/span&gt; 驱动的 &lt;span class=&#34;gap&#34;&gt;特殊过程&lt;/span&gt;。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;触发器类似约束，但是比约束更加灵活，可以实施更为复杂的检查和违约操作。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如下关于创建触发器的 SQL 语句，请回答相关问题&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;CREATE&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;TRIGGER&lt;/span&gt; SC_T&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;AFTER&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;UPDATE&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;ON&lt;/span&gt; SC&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;REFERENCING&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    OLD &lt;span class=&#34;token keyword&#34;&gt;AS&lt;/span&gt; OldTuple&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    NEW &lt;span class=&#34;token keyword&#34;&gt;AS&lt;/span&gt; NewTuple&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;FOR EACH ROW&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;WHEN&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;NewTuple&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Grade &lt;span class=&#34;token operator&#34;&gt;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1.1&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; OldTuple&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Grade&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;BEGIN&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;INSERT&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;INTO&lt;/span&gt; SC_U&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Sno&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Cno&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; OldGrade&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; NewGrade&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;VALUES&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;OldTuple&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sno&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; OldTuple&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Cno&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; OldTuple&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Grade&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; 			NewTuple&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Grade&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;END&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;code&gt;CREATE TRIGGER&lt;/code&gt;  后面要加触发器名。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在第 96 题的背景下， &lt;code&gt;AFTER UPDATE ON SC&lt;/code&gt;  的含义是在 SC 表更新后激活触发器。于是对应有 &lt;code&gt;BEFORE UPDATE ON SC&lt;/code&gt; ，表示触发器激活的时间是在执行除法事件前。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;格式为： &lt;code&gt;AFTER&lt;/code&gt;  |  &lt;code&gt;BEFORE&lt;/code&gt;  触发事件  &lt;code&gt;ON&lt;/code&gt;  表名。触发事件可以是 &lt;code&gt;INSERT&lt;/code&gt; 、 &lt;code&gt;DELETE&lt;/code&gt; 、 &lt;code&gt;UPDATE&lt;/code&gt; ，也可以是 &lt;code&gt;INSERT OR DELETE&lt;/code&gt; 、 &lt;code&gt;DELETE AND INSERT&lt;/code&gt; 。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在第 96 题的背景下，REFERENCING 指出引用的变量，如果触发事件是 UPDATE 操作，并且有 &lt;code&gt;FOR EACH ROW&lt;/code&gt;  子句，则可以引用的变量有 &lt;code&gt;OLD&lt;/code&gt;  和 &lt;code&gt;NEW&lt;/code&gt; ，分别表示修改之前的元组和修改之后的元组。若没有 &lt;code&gt;FOR EACH ROW&lt;/code&gt;  子句，则可以引用的变量有 &lt;code&gt;OLD TABLE&lt;/code&gt;  和 &lt;code&gt;NEW TABLE&lt;/code&gt; ，分别表示表中原来的内容和表中变化后的部分。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在第 96 题的背景下， &lt;code&gt;BEGIN&lt;/code&gt;  和 &lt;code&gt;END&lt;/code&gt;  之间的内容是动作体。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在 96 题的背景下， &lt;code&gt;FOR EACH ROW&lt;/code&gt;  定义了触发器的类型，指明动作体执行的频率。该语句的含义是对于 &lt;code&gt;UPDATE&lt;/code&gt;  执行了多少行，则触发器执行多少次。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;&lt;code&gt;FOR EACH STATEMENT&lt;/code&gt;  是语句级触发器。 &lt;code&gt;FOR EACH ROW&lt;/code&gt;  是行级触发器。语句级触发器是执行了触发事件的语句后执行一次动作体。行级触发器则是触发事件执行影响了多少行，则执行多少次动作体。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;101&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在第 96 题的背景下， &lt;code&gt;WHEN&lt;/code&gt;  () 的内容是触发条件，当触发条件为真时，动作体才执行，否则动作体不执行。如果省略 &lt;code&gt;WHEN&lt;/code&gt;  触发条件，则在触发事件引发的触发器激活后就立即执行动作体。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;删除触发器的 SQL 语句格式是： &lt;code&gt;DROP TRIGGER 触发器名 ON 表名&lt;/code&gt; 。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;未完待续...&lt;/p&gt;
&lt;/div&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;参考教材：清华大学《编译原理》第三版。&lt;br /&gt;
另参考：本人的编译原理老师的授课内容。&lt;br /&gt;
如有错误，欢迎指正。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;目的：梳理编译原理课程的核心知识，另一方面为了更好地备考期末。&lt;br /&gt;
形式：目录罗列知识结构、问答题强化知识、信息栏回忆知识。&lt;br /&gt;
每次我将这些知识总结、整理到博客上时，内心都很满足和愉悦。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;概论&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#概论&#34;&gt;#&lt;/a&gt; 概论&lt;/h1&gt;
&lt;h2 id=&#34;编译过程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编译过程&#34;&gt;#&lt;/a&gt; 编译过程&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;词法分析是编译过程第一个阶段。这个阶段的任务是从左到右一个字符一个字符地输入源程序，对构成源程序的字符流进行扫描和分解，从而识别出一个个单词。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;语法分析是编译过程的第二个阶段。语法分析在词法分析的基础上将单词序列分解成各类语法短语，得到抽象语法树。语法分析依据的是语言的语法规则，通过语法分析确定整个输入串是否构成一个语法上正确的程序。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;语义分析审查源程序有无语义错误，为代码生成阶段收集类型信息。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;中间代码生成将源程序变成一种内部表示形式，即中间代码，这是一种结构简单、含义明确的记号系统。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;代码优化是对前一阶段产生的中间代码进行变换或改造，目的是使得生成的目标代码更加高效，节省时间与空间。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;目标代码生成把中间代码变换成特定机器上的绝对指令代码或可重定位的指令代码或汇编指令代码，与硬件系统结构和指令含义有关。&lt;/p&gt;
&lt;/div&gt;
&lt;ol&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;编译过程主要有哪几个阶段？ &lt;span class=&#34;gap&#34;&gt;词法分析、语法分析、语义分析、中间代码生成、代码优化、目标代码生成&lt;/span&gt;。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察编译原理的基本认识。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;词法分析的输入是什么？输出是什么？ &lt;span class=&#34;gap&#34;&gt;输入是字符，输出是单词（token）序列&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察词法分析的输入和输出。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;语法分析的输入是什么？输出是什么？ &lt;span class=&#34;gap&#34;&gt;输入是词法分析输出的 token 序列，输出一般是抽象语法树&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察语法分析的输入和输出。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;语义分析的输入是什么？输出是什么？ &lt;span class=&#34;gap&#34;&gt;输入输出均为标识符。具体来说，输入是 token ($id, 标识符名表地址)，输出是新的 token ($id, 符号表地址)&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz&#34;&gt;
&lt;p&gt;中间代码的一种常见形式是近似 “三地址指令” 的四元式，请问四元式形式是 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;。&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;(运算符，运算对象 1，运算对象 2，结果)&lt;/li&gt;
&lt;li&gt;(运算对象 1，运算符，运算对象 2，结果)&lt;/li&gt;
&lt;li&gt;(结果，运算符，运算对象 1，运算对象 2)&lt;/li&gt;
&lt;li&gt;(运算符，运算对象 1，运算对象 2)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;编译程序的结构-编译阶段的组合&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编译程序的结构-编译阶段的组合&#34;&gt;#&lt;/a&gt; 编译程序的结构、编译阶段的组合&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;编译阶段的前端：主要依赖于源语言而与目标机无关。&lt;br /&gt;
编译阶段的后端：依赖于目标机而一般不依赖于源语言，只与中间代码有关的那些阶段的工作。&lt;/p&gt;
&lt;p&gt;一个编译过程可由一遍、两遍或多遍完成，一遍完成的编译过程称为单遍扫描，两遍或多遍完成的编译过程称为多遍扫描。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;上述编译过程的 6 个阶段的任务可以分别由 6 个模块完成，分别称作词法分析程序、语法分析程序、语义分析程序、中间代码生成程序、代码优化程序和目标代码生成程序。此外，一个完整的编译程序还必须包括 &lt;span class=&#34;gap&#34;&gt;表格管理程序和出错处理程序&lt;/span&gt;。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察对编译程序的全面认识。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;编译阶段的前端有哪些阶段？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;词法分析&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;语法分析&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;语义分析&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;中间代码生成&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;考察编译阶段的前端。&lt;br /&gt;
某些代码优化工作也可在前端做，还包括与前端每个阶段相关的出错处理工作和符号表管理工作。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz multi&#34;&gt;
&lt;p&gt;编译阶段的后端主要有哪些工作？&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li&gt;词法分析&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;目标代码生成阶段&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;出错处理工作&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;符号表管理工作&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;考察编译阶段的后端。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz&#34;&gt;
&lt;p&gt;占内存空间少，但时间消耗大的扫描方式是？ &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;多遍扫描&lt;/li&gt;
&lt;li&gt;单遍扫描&lt;/li&gt;
&lt;li&gt;两者都是&lt;/li&gt;
&lt;li&gt;不知道&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;单遍扫描时间消耗小，但是占内存空间大，需要一次性存储所有信息。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;解释程序与存储组织&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#解释程序与存储组织&#34;&gt;#&lt;/a&gt; 解释程序与存储组织&lt;/h2&gt;
&lt;ol start=&#34;10&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;解释程序一个个的获取、分析并执行源程序语句，一旦第一个语句分析结束，源程序便开始运行并且生成结果，它特别适合程序员以 &lt;span class=&#34;gap&#34;&gt;交互方式&lt;/span&gt; 工作的情况。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;程序的解释是非常慢的。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;在编译阶段，存储区主要为 &lt;span class=&#34;gap&#34;&gt;源程序 (中间形式)&lt;/span&gt; 和&lt;span class=&#34;gap&#34;&gt;目标代码&lt;/span&gt; 开辟空间，要存放编译需要的各种 &lt;span class=&#34;gap&#34;&gt;表格&lt;/span&gt;。在运行阶段，存储区主要是 &lt;span class=&#34;gap&#34;&gt;目标代码&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;数据&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;对下列错误信息，请指出可能是编译的哪个阶段（词法分析、语法分析、语义分析、代码生成）报告的。&lt;br /&gt;
(1) else 没有匹配的 if。 &lt;span class=&#34;gap&#34;&gt;语法分析&lt;/span&gt;&lt;br /&gt;
 (2) 数组下标越界。&lt;span class=&#34;gap&#34;&gt;语义分析&lt;/span&gt;&lt;br /&gt;
 (3) 使用的函数没有定义。&lt;span class=&#34;gap&#34;&gt;语法分析&lt;/span&gt;&lt;br /&gt;
 (4) 在数中出现非数字字符。 &lt;span class=&#34;gap&#34;&gt;词法分析&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;语法分析通常解决匹配问题。如，使用的函数没有定义，说明没有声明部分与之匹配。又如第一题的 else 没有与 if 匹配。&lt;br /&gt;
跟字符有关的通常是词法分析&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;文法和语言&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#文法和语言&#34;&gt;#&lt;/a&gt; 文法和语言&lt;/h1&gt;
&lt;h2 id=&#34;形式定义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#形式定义&#34;&gt;#&lt;/a&gt; 形式定义&lt;/h2&gt;
&lt;ol start=&#34;13&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;文法 G 定义为四元组（V,Q,P,S）。其中，V 是 &lt;span class=&#34;gap&#34;&gt;非终结符集&lt;/span&gt;；Q 是 &lt;span class=&#34;gap&#34;&gt;终结符集&lt;/span&gt;；P 是 &lt;span class=&#34;gap&#34;&gt;一组产生式&lt;/span&gt;；S 是 &lt;span class=&#34;gap&#34;&gt;文法初始符&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;终结符通常用什么表示？&lt;span class=&#34;gap&#34;&gt;小写字母&lt;/span&gt; 非终结符通常用什么表示？&lt;span class=&#34;gap&#34;&gt;大写字母&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;ABsa 是句子？（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;所有字符为终结符才是句子。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;B-&amp;gt;dAaui，则 dAaui 是句型？（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;句型是推导得到的符号串，可由终结符和非终结符组成。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;文法描述的语言是该文法一切 &lt;span class=&#34;gap&#34;&gt;句子&lt;/span&gt; 的集合。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;文法类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#文法类型&#34;&gt;#&lt;/a&gt; 文法类型&lt;/h2&gt;
&lt;ol start=&#34;18&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;如果一个文法的每个产生式左部至少含一个非终结符，则这种文法是 &lt;span class=&#34;gap&#34;&gt;0 型文法&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;0 型文法又称为短语文法。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;如果一个文法的每个产生式左部只有一个非终结符，则这种文法是 &lt;span class=&#34;gap&#34;&gt;2 型文法&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;2 型文法又称为上下文无关文法，是当前语言使用最多的文法。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;如果一个文法的每个产生式的形式都是 A-&amp;gt;aB 或 A-&amp;gt;a，则这种文法是 &lt;span class=&#34;gap&#34;&gt;正规文法&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;正规文法即为 3 型文法。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;如果一种文法的每个产生式右部的符号个数不少于左部符号的个数，则这种文法是 &lt;span class=&#34;gap&#34;&gt;1 型文法&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;1 型文法又称为上下文有关文法。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;语法树&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#语法树&#34;&gt;#&lt;/a&gt; 语法树&lt;/h2&gt;
&lt;ol start=&#34;22&#34;&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;给定一个文法，其语法树唯一。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;对于一个文法，语法树不一定唯一。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;语法树结构中，根节点一定是文法开始符。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;语法树结构中，叶结点一定是终结符。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;叶结点可以是终结符也可以是空串。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;最右推导是规范推导。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;最右推导得到的句型称为右句型。最左推导得到的句型称为左句型。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;每个句子都有最左推导和最右推导，但是每个句型不一定有最左推导和最右推导。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;当某个文法中存在某个句子有两个不同的最左（最右）推导，则这个文法是二义的。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;语法分析初步&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#语法分析初步&#34;&gt;#&lt;/a&gt; 语法分析初步&lt;/h2&gt;
&lt;ol start=&#34;28&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;文法的短语是文法初始符经过多步推导得到的所有子串。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;短语中经过一步推导得到的子串称为直接短语。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;直接短语又称为简单短语。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;该文法的句柄是该文法最后一步推导得到的直接短语。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;句柄只适用于左句型。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;句柄只适用于右句型，因此通常用最右推导求句柄。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;自顶向下语法分析方法的关键是什么？ &lt;span class=&#34;gap&#34;&gt;寻找候选式&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;自底向上语法分析方法的关键是什么？ &lt;span class=&#34;gap&#34;&gt;寻找句柄&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;规范推导的逆过程是规范规约。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;错！规范推导的逆过程是规范归约。“归”。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;闭包比正闭包多了空串。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;值得一提的是，你需要掌握根据给定文法，使用最右推导和语法树，求某个给定句型或句子的短语、直接短语、句柄。&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;你需要了解的文法描述能力对比图：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../../assets/wadawdawd.png&#34; alt=&#34;image&#34; /&gt;&lt;/p&gt;
&lt;p&gt;很明显，从中能够看到几个特点：&lt;br /&gt;
（1）LL (k) 文法仅仅只能表现 LR (k) 文法的一部分。&lt;br /&gt;
（2）（k）一定比（k-1）的描述能力更强，毕竟较后者多一个展望符。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;词法分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#词法分析&#34;&gt;#&lt;/a&gt; 词法分析&lt;/h1&gt;
&lt;h2 id=&#34;词法分析与语法分析的接口方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#词法分析与语法分析的接口方式&#34;&gt;#&lt;/a&gt; 词法分析与语法分析的接口方式&lt;/h2&gt;
&lt;ol start=&#34;36&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;词法分析与语法分析的协同工作关系决定了两者之间存在接口方式的规定，最容易想到的方式是词法分析工作是独立的一遍，把字符流的源程序变为 &lt;span class=&#34;gap&#34;&gt;单词序列（token）&lt;/span&gt;，输出到一个中间文件，以供语法分析使用。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察词法分析的输出。词法分析的输出是单词序列（token）&lt;br /&gt;
词法分析的接口方式还有两种，一种是词法分析程序作为语法分析程序的子程序，当语法分析程序需要一个单词时，就调用词法分析程序。还有一种是协同程序方式，词法分析程序与语法分析程序以生产者消费者的方式同步进行。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;你能想到的词法分析任务有哪些？&lt;span class=&#34;gap&#34;&gt;如下&lt;/span&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;（1）组织源程序的输入。（2）删除注释，无用空格。（3）查填标识符名表。（4）检查词法错误。（5）记录遇到的换行符个数，以便提供词法报错信息。（6）识别单词，转换成机内表示形式，即 token 的二元式表示。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;标识符名表&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#标识符名表&#34;&gt;#&lt;/a&gt; 标识符名表&lt;/h2&gt;
&lt;ol start=&#34;38&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;token 的机内表示方式采用二元式表示：（单词种别，单词自身值），如常数 5 的二元式是（2,&#39;5&#39;），其中，2 这个编码代表种类是常数，&#39;5&#39; 代表值。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;所有 token 的二元式形成的表格称为标识符名表。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;token 中，关键字、界限符、运算符的单词类别编码足以表示其完整信息，因此对于这些 token，它们二元组的单词属性值常为空。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;标识符的 token 的二元式表示为：（标识符的类别编码，指向该标识符所在符号表中位置的指针）（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;标识符名表就是符号表。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;标识符名表常用于词法分析，而符号表常用于语义分析。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;正规文法和正规式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#正规文法和正规式&#34;&gt;#&lt;/a&gt; 正规文法和正规式&lt;/h2&gt;
&lt;ol start=&#34;43&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;正规式又称为正则表达式，也可以认为是字符串的形式规则，这种规则能表示的所有字符串的集合称为正规集。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;空串不是正规式。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;一个字符也能是正规式。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如果 a,b 是正规式，那么 (a)、a|b、a・b、a * 也是正规式（* 表示闭包）。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;(a|b)* 等价于 (a|b)(a|b)...(a|b)。(a*|b*) 等价于 (a|b)*。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;如果 d 表示 0-9 中的数字，那么 dd * 可以表示空串。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;dd * 表示至少一个数字。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;若两个正规式 a 和 b 所表示的 &lt;span class=&#34;gap&#34;&gt;正规集&lt;/span&gt; 相同，则说 a 和 b 等价。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;交代一些正规式的代数规律：&lt;br /&gt;
（1）r|s = s|r	“或” 满足交换律&lt;br /&gt;
（2）r|(s|t)=(r|s)|t		&amp;quot;或&amp;quot; 的可结合律&lt;br /&gt;
（3）(rs) t=r (st)		&amp;quot;连接&amp;quot; 的可结合律（“连接” 可以理解为 “与”）&lt;br /&gt;
（4）r (s|t)=rs|rt, (s|t) r=sr|tr		分配律&lt;br /&gt;
（5）&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;r=r, r&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;=r		&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 “连接” 的恒等元素&lt;br /&gt;
（6）r|r=r	“或” 的抽取律&lt;br /&gt;
（7）r**=r		幂等性&lt;br /&gt;
（8）r*=(r|&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;)*		闭包一定包含空串&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;有穷自动机&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#有穷自动机&#34;&gt;#&lt;/a&gt; 有穷自动机&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;有穷自动机 FA 作为一种识别装置，能准确地识别正规集。&lt;br /&gt;
有穷自动机分为两类：确定地有穷自动机 DFA 和不确定地有穷自动机 NFA。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;50&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;一个确定的有穷自动机 DFA 可以用五元组 M 表示：M=(K,&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.00001em;vertical-align:-0.25001em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;,&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;,S,Z)。K 是 &lt;span class=&#34;gap&#34;&gt;状态集&lt;/span&gt;。&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.00001em;vertical-align:-0.25001em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 &lt;span class=&#34;gap&#34;&gt;输入符号表&lt;/span&gt;。&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 &lt;span class=&#34;gap&#34;&gt;转换函数&lt;/span&gt;。S 是 &lt;span class=&#34;gap&#34;&gt;初始状态&lt;/span&gt;。Z 是 &lt;span class=&#34;gap&#34;&gt;终态集&lt;/span&gt;。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察 DFA 的五要素。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;DFA 只能有一个初始状态，但是可以有多个终态。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;DFA 可以表示成一个状态图。其中，初态状态冠以 =&amp;gt;，终态用双圈表示。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察 DFA 状态图。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;DFA 状态图的弧上允许有空串。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;DFA 不允许空串转换。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;DFA 还可以表示成一个状态表，行表示状态，列表示输入符号，矩阵元素表示相应状态经过输入符号转换的新状态。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;考察 DFA 状态转换表&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;一个符号串，能被自动机识别，在于从初始状态到终止状态存在一条道路。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;DFA 的状态图中，从一个状态结点出发的弧的数量是无限制的。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;DFA 的每个状态结点，只能伸出 n 条弧，这个 n 是输入符号表的长度，即状态转换表中有效列的个数。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;一个不确定的有穷自动机 NFA 能被一个五元组表示：M=(K,&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.00001em;vertical-align:-0.25001em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;,&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;,S,Z)，其中 K 是状态集、&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.00001em;vertical-align:-0.25001em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是输入符号表、&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是转换函数、S 是 &lt;span class=&#34;gap&#34;&gt;非空状态集&lt;/span&gt;、Z 是终态集。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;NFA 的初态可以不止一个。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;NFA 的状态图的弧上允许有空串。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;NFA 的状态图中，每个状态结点伸出的弧的数量没有限制。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;值得一提的是，你需要掌握将 NFA 转换为 DFA，使用子集构造法对 DFA 最小化，并判断给定的符号串能否被最小化 DFA 识别。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;自顶向下语法分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自顶向下语法分析&#34;&gt;#&lt;/a&gt; 自顶向下语法分析&lt;/h1&gt;
&lt;h2 id=&#34;自顶向下思想&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自顶向下思想&#34;&gt;#&lt;/a&gt; 自顶向下思想&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;自顶向下分析方法从文法的开始符号出发企图推导出与输入的单词符号串完全相匹配的句子，若输入串是给定文法的句子，则必能推出，反之必然出错。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;60&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;LL (1) 分析方法有递归下降分析方法和表驱动的 LL (1) 分析方法。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;自顶向下分析方法的四个动作是 &lt;span class=&#34;gap&#34;&gt;推导&lt;/span&gt; -&amp;gt; &lt;span class=&#34;gap&#34;&gt;匹配&lt;/span&gt; -&amp;gt; 成功 -&amp;gt; 报错&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;自顶向下分析方法分为确定的自顶向下分析方法和不确定的自顶向下分析方法。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;递归下降方法和 LL (k) 分析方法都属于不确定的自顶向下分析方法。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;都属于确定的自顶向下分析方法。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;确定的自顶向下分析方法要尽可能地消除 &lt;span class=&#34;gap&#34;&gt;回溯&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;确定的自顶向下分析方法的 “确定” 含义在于，对于一个非终结符，通过给定的一个输入字符，推导得到的符号串是唯一的。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;换言之，一个非终结符，通过给定的输入符号，选择的候选式是唯一的，而不确定的自顶向下分析方法选择的候选式是不唯一的。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;ll1分析方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ll1分析方法&#34;&gt;#&lt;/a&gt; LL（1）分析方法&lt;/h2&gt;
&lt;ol start=&#34;66&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;FIRST 集允许有空串。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;尾符（$、#）可含于 FOLLOW 集中，而空串不能。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;文法初始符的 FOLLOW 集一定不包含尾符。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;FOLLOW 集由于文法初始符一定包含尾符，故 FOLLOW 集可以包含尾符。同时，FOLLOW 集还不允许包含空串。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;给定上下文无关文法的产生式 A-&amp;gt;aBc，若 B 导空，则 A 导空。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;导空条件是右部的所有文法符号均导空，不能只导空一个。换言之，只要出现一个终结符，这个产生式左部对应的非终结符一定不导空。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;给定上下文无关文法的产生式 A-&amp;gt;a，如果 a 不导空，则该产生式的 SELECT 集为 FIRST (a)。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;给定上下文无关文法的产生式 A-&amp;gt;a，如果 a 导空，则该产生式的 SELECT 集为 FIRST (a)&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;FOLLOW(A)。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;(FIRST(a) - &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FOLLOW(A)&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;一个上下文无关文法是 LL (1) 文法的充分必要条件是，对每个非终结符 A 的所有不同产生式，以两个为例，A-&amp;gt;a, A-&amp;gt;b，满足 SELECT (A-&amp;gt;a) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∩&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cap&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∩&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; SELECT (A-&amp;gt;b) 等于空集。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;LL (1) 的第一个 L 含义是使用最左推导，第二个 L 的含义是自左向右扫描输入串。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;1 表明只需向右看一个符号便可决定如何推导。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;如果 A 和 B 均为非终结符，则 FIRST (AB) = FIRST (A)。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;FIRST (AB) = FIRST (A) 和 FIRST (B) 的并集。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如果产生式 X-&amp;gt;aB，则 FIRST (X)={a}。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如果产生式 X-&amp;gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，则 FIRST (X)={&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;}。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如果产生式 X-&amp;gt;Ab，A 不可导空，则 FIRST (X)=FIRST (A)。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;如果产生式 X-&amp;gt;ABCD，A,B,C 均导空，D 不可导空，则 FIRST (X)=FIRST (A) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(B) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(C) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(D)。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;正确的公式应该是：FIRST (X)=(FIRST (A)-&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; (FIRST(B)-&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; (FIRST(C)-&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(D)。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;如果产生式 X-&amp;gt;ABCD，A,B,C,D 均导空，则 FIRST (X)=FIRST (A) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(B) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(C) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(D)。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;正确的公式应该是：FIRST (X)=FIRST (A) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(B) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(C) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.55556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; FIRST(D) &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∪&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;{&lt;/mo&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;}&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cup \{\epsilon\}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∪&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;{&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;}&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如果有上下文无关文法的产生式 A-&amp;gt;aBC，C 是非终结符 B 后面的文法符号串，则 FOLLOW (B) 一定包含 FIRST (C)。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在第 80 题的基础上，如果 C 导空（如 C 实际上是多个非终结符 DEF，D,E,F 均导空），则 FOLLOW (B) 还包含 FOLLOW (A)。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;求文法的所有非终结符的 FOLLOW 时，当每个非终结符的 FOLLOW 集不再增大时停止。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;一个 LL (1) 文法一定不存在左递归和左公因子。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;递归下降分析方法也需要每个非终结符的所有产生式满足 SELECT 集的交集为空。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;使用表驱动的 LL (1) 分析方法对输入符号串进行一栈一流分析时，当且仅当栈顶为 [尾符 ($ 或 #)]，而且输入流指针指向 [尾符 ($ 或 #)]，两者匹配才表示该输入字符串符合文法。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;表驱动的 LL (1) 分析方法在对输入符号串进行一栈一流分析时，栈中的非终结符选择候选式进行推导展开时，输入流不变。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;对，输入流顶部字符被抵消，当且仅当栈顶元素与输入流顶部字符匹配。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如果栈的顶部是非终结符 A，则要选择与当前输入符相匹配的 A 的产生式，并用该产生式的右部替换栈顶的非终结符。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;一栈一流分析的分析栈从文法初始符开始。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz false&#34;&gt;
&lt;p&gt;LL (1) 预测分析表的行只有非终结符，列只有输入符和空串。（）&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;列不含空串，而且不只含输入符，还包含尾符。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;递归下降分析方法内存要求高，适用于小规模文法。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;预测分析表每个矩阵元素的内容是一条关于某个非终结符 A 的产生式，表明当用非终结符 A 向下推导时，面临输入符 a 时所应采取的候选产生式。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;自底向上语法分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自底向上语法分析&#34;&gt;#&lt;/a&gt; 自底向上语法分析&lt;/h1&gt;
&lt;h2 id=&#34;基本思想&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基本思想&#34;&gt;#&lt;/a&gt; 基本思想&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;自底向上是对输入符号串自左向右扫描，并将输入符号逐个移入一个后进先出栈中，边移入边分析，一旦栈顶符号串形成某个句型的句柄或其他可归约串时就进行归约。归约的结果是将句柄或其他可归约串从栈顶部分弹出，而将相应的非终结符压入栈中。重复这个过程直到归约到栈中只剩文法初始符时则为分析成功，也就确认了输入串是文法的句子。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;92&#34;&gt;
&lt;li class=&#34;quiz&#34;&gt;
&lt;p&gt;自底向上分析方法的四个动作是什么？ &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li class=&#34;correct&#34;&gt;移入、归约、成功、报错。&lt;/li&gt;
&lt;li&gt;推导、匹配、成功、报错。&lt;/li&gt;
&lt;li&gt;移入、匹配、成功、报错。&lt;/li&gt;
&lt;li&gt;推导、归约、成功、报错。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz&#34;&gt;
&lt;p&gt;自底向上四个动作中移入是将输入符号从输入流中移入到 &lt;span class=&#34;gap&#34;&gt;&lt;/span&gt;。&lt;/p&gt;
&lt;ul class=&#34;options&#34;&gt;
&lt;li&gt;状态栈。&lt;/li&gt;
&lt;li class=&#34;correct&#34;&gt;符号分析栈。&lt;/li&gt;
&lt;li&gt;ACTION 表。&lt;/li&gt;
&lt;li&gt;GOTO 表。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;符号分析栈从尾符开始。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;lr0分析方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#lr0分析方法&#34;&gt;#&lt;/a&gt; LR (0) 分析方法&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;LR 分析基本思想是：（1）历史信息：记住已经移入和归约的整个符号串。（2）预测信息：根据所用的产生式推测未来可能遇到的符号。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;95&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;LR (k) 中的 L 的含义是 &lt;span class=&#34;gap&#34;&gt;自左向右扫描输入流&lt;/span&gt;；R 的含义是 &lt;span class=&#34;gap&#34;&gt;构造最右推导的逆&lt;/span&gt;；k 的含义是 &lt;span class=&#34;gap&#34;&gt;分析动作向前所看的输入流符号个数&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;LR (k) 分析方法相较 LL (k) 分析方法和自底向上优先分析方法的优点是 &lt;span class=&#34;gap&#34;&gt;分析速度快，准确，对文法限制少，能指出出错位置&lt;/span&gt;，相应的缺点是 &lt;span class=&#34;gap&#34;&gt;对一个实用语言文法的分析器的构造工作量相当大&lt;/span&gt;	&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;你可能需要掌握消除一个文法中的空产生式的算法。&lt;/p&gt;
&lt;/div&gt;
&lt;ol start=&#34;97&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;为了防止文法初始符出现在文法产生式右部，在原文法 G [S] 中增加产生式 S&#39;-&amp;gt;S，S 为原文法 G 的开始符号，所得的新文法 G&#39; 称为原文法 G 的 &lt;span class=&#34;gap&#34;&gt;拓广文法&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;在文法 G 中每个产生式的右部适当位置添加一个圆点构成 &lt;span class=&#34;gap&#34;&gt;项目&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;一个产生式 S-&amp;gt;aAcBe 对应有 6 个项目：[0] S-&amp;gt;.aAcBe,[1] S-&amp;gt;a.AcBe, [2] S-&amp;gt;aA.cBe,[3] S-&amp;gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2FBYy5CZQ==&#34;&gt;aAc.Be&lt;/span&gt;,[4] S-&amp;gt;aAcB.e,[5] S-&amp;gt;aAcBe.。归约项目是圆点在产生式最右端的 LR (0) 项目，如 &lt;span class=&#34;gap&#34;&gt;[5]&lt;/span&gt;。接受项目是对文法初始符的归约项目，即 [[5]]。待约项目是圆点后第一个符号为非终结符的 LR (0) 项目，如 &lt;span class=&#34;gap&#34;&gt;[1]&lt;/span&gt; 和&lt;span class=&#34;gap&#34;&gt; [3]&lt;/span&gt;。移入项目是圆点后第一个符号为终结符的 LR (0) 项目，如 &lt;span class=&#34;gap&#34;&gt;[0]&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;[2]&lt;/span&gt; 和 &lt;span class=&#34;gap&#34;&gt;[4]&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz&#34; ,fill=&#34;&#34;&gt;
&lt;p&gt;若句型&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;mi&gt;β&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha \beta&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05278em;&#34;&gt;β&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 中，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;β&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\beta&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05278em;&#34;&gt;β&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是终结符串或空串，（说明&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是非终结符串），则&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 &lt;span class=&#34;gap&#34;&gt;前缀&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;若作为前缀的&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 不含句柄或含一个句柄且具有形式&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;π&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha=\alpha&amp;#x27;\pi&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;π&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;（&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;π&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\pi&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;π&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是句柄），则称前缀&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 &lt;span class=&#34;gap&#34;&gt;活前缀&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;若&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是含句柄的活前缀，即有&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;π&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha=\alpha&amp;#x27;\pi&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;π&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，且&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;π&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\pi&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;π&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是句柄，则&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 &lt;span class=&#34;gap&#34;&gt;归约活前缀&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;若有项目集 IS={.abd [1], .abc [2], .bc [3], .de [4], de.c [5]}，则项目集 IS 对 a 做投影 IS (a)={&lt;span class=&#34;gap&#34;&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2EuYmQ=&#34;&gt;a.bd&lt;/span&gt;[1]&lt;/span&gt;,&lt;span&gt;a.bc[2]&lt;/span&gt;{.gap}}。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code&gt;&amp;gt; 以此类推，IS(b)=&amp;#123;b\.c[3]&amp;#125;, IS(c)=&amp;#123;dec\.[5]&amp;#125;。
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;104&#34;&gt;
&lt;li&gt;例如有如下文法 G [E&#39;]：&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight raw&#34;&gt;&lt;figcaption data-lang=&#34;&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;(1) E&amp;#39;-&amp;gt;E&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;(2) E-&amp;gt;T&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;(3) T-&amp;gt;F&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;(4) F-&amp;gt;id&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;(5) E-&amp;gt;E+T&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;(6) T-&amp;gt;T*F&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;(7) F-&amp;gt;(E)&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p class=&#34;options&#34;&gt;则产生式 E&#39;-&amp;gt;E 关于项目 I={E&#39;-&amp;gt;.E} 闭包 CLOSURE ([E&#39;-&amp;gt;.E]) 为？{.quiz .multi}&lt;br /&gt;
- E&#39;-&amp;gt;.E {.correct}&lt;br /&gt;
- E-&amp;gt;.T {.correct}&lt;br /&gt;
- E-&amp;gt;.E+T {.correct}&lt;br /&gt;
- E-&amp;gt;E+.T&lt;br /&gt;
- T-&amp;gt;F.&lt;br /&gt;
- T-&amp;gt;.F {.correct}&lt;br /&gt;
- T-&amp;gt;.T*F {.correct}&lt;br /&gt;
- F-&amp;gt;.id {.correct}&lt;br /&gt;
- F-&amp;gt;.(E) {.correct}&lt;br /&gt;
- F-&amp;gt;id.&lt;/p&gt;
&lt;ol start=&#34;105&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;LR (0) 项目集规范族又称为 &lt;span class=&#34;gap&#34;&gt;LRSM&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;LR 自动机&lt;/span&gt;、&lt;span class=&#34;gap&#34;&gt;DFSA&lt;/span&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;如下项目集：&lt;br /&gt;
A-&amp;gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;.&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;mi&gt;β&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha\beta&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05278em;&#34;&gt;β&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br /&gt;
B-&amp;gt;\gama.&lt;br /&gt;
 存在 &lt;span class=&#34;gap&#34;&gt;移入 - 归约&lt;/span&gt;冲突。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;如下项目集：&lt;br /&gt;
A-&amp;gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;β&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\beta&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05278em;&#34;&gt;β&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;.&lt;br /&gt;
B-&amp;gt;\gama.&lt;br /&gt;
 存在 &lt;span class=&#34;gap&#34;&gt;归约 - 归约&lt;/span&gt;冲突。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;对一个文法的 LR (0) 项目集规范族不存在 &lt;span class=&#34;gap&#34;&gt;移入 - 归约冲突&lt;/span&gt;或 &lt;span class=&#34;gap&#34;&gt;归约 - 归约冲突&lt;/span&gt;时，称这个文法是 LR (0) 文法。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code&gt;&amp;gt; LR(0)文法的项目集规范族的任何状态都不允许存在移入-归约冲突和归约-归约冲突。
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;109&#34;&gt;
&lt;li class=&#34;quiz fill&#34;&gt;
&lt;p&gt;LR (0) 分析表由 &lt;span class=&#34;gap&#34;&gt;ACTION 表&lt;/span&gt;和&lt;span class=&#34;gap&#34;&gt; GOTO 表&lt;/span&gt;组成。&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;LR (0) 分析表中的 ACTION 表的列标是终结符和尾符。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;LR (0) 分析表中的 GOTO 表的列标是非终结符。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;ACTION [k,a] 为 S_j 的含义是，在状态 k，遇到终结符 a，将终结符 a 移入符号栈，将状态 j 压入状态栈。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;ACTION [k,a] 为 r_j 的含义是，在状态 k 使用第 j 个产生式（记为 S）对符号栈中的句柄进行归约，弹出符号栈中与 S 同长的符号，弹出状态栈中与 S 同长的状态，同时将 S 的左部非终结符（记为 M）压入栈顶，根据项目集规范族，查看状态栈栈顶非终结符遇到 M 能够 GOTO 到哪个状态（记为 k&#39;），将 k&#39; 压入状态栈栈顶。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;LR (0) 分析表的行号的含义是状态，从 0 开始。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;找到包含能够归约到文法初始符的接受项目 I，在 LR (0) 分析表中，置 ACTION [I, 尾符]=acc，表示接受。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;slr1分析方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#slr1分析方法&#34;&gt;#&lt;/a&gt; SLR (1) 分析方法&lt;/h2&gt;
&lt;ol start=&#34;116&#34;&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;如果 LR (0) 项目集规范族存在归约 - 归约冲突或移入 - 归约冲突，则这个文法不是 LR (0) 文法。例如，此时出现归约 - 归约冲突的状态涉及的产生式为：A-&amp;gt;\gama.,B-&amp;gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;θ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\theta&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;θ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;.。对所有涉及归约 - 归约冲突状态的产生式的左部非终结符求 FOLLOW 集。如果它们的 FOLLOW 集彼此互不相交，则这个文法是 SLR (1) 文法。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;在第 116 题的基础上，对于出现移入 - 归约冲突状态涉及的产生式为：X-&amp;gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\alpha&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;.b&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;β&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\beta&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05278em;&#34;&gt;β&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;,A-&amp;gt;\gama。移入项目的展望符为 b，如果满足归约项目的左部非终结符的 FOLLOW 集与展望符交集为空，那么这个文法依然是 SLR (1) 文法。（）&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;quiz true&#34;&gt;
&lt;p&gt;对于 SLR (1) 文法，在冲突状态中，如果输入符号 a 等于移入项目的展望符 b，则选择移入。如果输入符号 a 是某个非终结符的 FOLLOW 集的一个元素，那么则使用这个终结符的产生式进行归约。（）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;前因&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;第一次听说具身智能是在 5 月份去重庆参加 VALSE2024 会议的报告上，今天才开始正式了解具身智能。正好为了应付一下选修课的期末论文作业，就拿这个充当一下，顺便也学习具身智能。&lt;br /&gt;


	&lt;div class=&#34;row&#34;&gt;
    &lt;embed src=&#34;/pdf/Embodied_AI_A_Survey.pdf&#34; width=&#34;100%&#34; height=&#34;550&#34; type=&#34;application/pdf&#34;&gt;
	&lt;/div&gt;


&lt;/p&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;起因&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;今天 24 年 12 月 8 号下午打球，被暴虐后心有不甘，晚上看了好几个羽毛球的教学视频。结合本博客具备的视频播放能力，故产生了记录学习羽毛球的知识。这篇博客是第一期。&lt;/p&gt;
&lt;div class=&#34;note danger&#34;&gt;
&lt;p&gt;本博客的视频均仅供学习使用，请勿不经原作者许可用于商业行为。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;正手杀球握拍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#正手杀球握拍&#34;&gt;#&lt;/a&gt; 正手杀球握拍&lt;/h1&gt;
&lt;p&gt;每次打完球，手腕总是痛的不行。今天观察发现，自己每次杀球后手腕总是十分疼，像抽筋了一样，于是怀疑自己是不是握拍、动作等基础知识不掌握，12 月 8 号当日下午打完球后的晚上，看到刘辉教练讲的正手杀球握拍，发现自己的握拍有相当大的问题，根本不科学。搬运视频：&lt;/p&gt;
&lt;p&gt;
&lt;div style=&#34;position: relative; width: 100%; height: 0; padding-bottom: 75%;&#34;&gt;
    &lt;iframe src=&#34;//player.bilibili.com/player.html?isOutside=true&amp;aid=530219379&amp;bvid=BV1Nu411h7ZP&amp;cid=1175166328&amp;p=1&amp;autoplay=0&#34; scrolling=&#34;no&#34; border=&#34;0&#34; frameborder=&#34;no&#34; framespacing=&#34;0&#34; allowfullscreen=&#34;true&#34; style=&#34;position:absolute; height: 100%; width: 100%;&#34;&gt;&lt;/iframe&gt;
&lt;/div&gt;
&lt;/p&gt;
&lt;p&gt;关键点是，我的杀球握拍并不是视频中所说的拳式，虎口也不是紧闭的。相反，我现在错误的杀球握拍是虎口半张，右手大拇指正压着羽毛球拍的侧棱。正确的是，虎口应该紧闭，而且大拇指应该紧扣食指，而非贴着羽毛球拍的侧棱。&lt;/p&gt;
&lt;h1 id=&#34;正手高远球握拍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#正手高远球握拍&#34;&gt;#&lt;/a&gt; 正手高远球握拍&lt;/h1&gt;
&lt;p&gt;进一步，我也观察到自己的正手高远球打不远，而且打完总是手腕很疼，也怀疑在握拍和动作上存在不正确的地方，在我继续看刘辉教练的正手高远球握拍视频后，再一次猛然醒悟。搬运视频：&lt;/p&gt;
&lt;p&gt;
&lt;div style=&#34;position: relative; width: 100%; height: 0; padding-bottom: 75%;&#34;&gt;
    &lt;iframe src=&#34;//player.bilibili.com/player.html?isOutside=true&amp;aid=113077966078585&amp;bvid=BV1GKpceMExM&amp;cid=25732253961&amp;p=1&amp;autoplay=0&#34; scrolling=&#34;no&#34; border=&#34;0&#34; frameborder=&#34;no&#34; framespacing=&#34;0&#34; allowfullscreen=&#34;true&#34; style=&#34;position:absolute; height: 100%; width: 100%;&#34;&gt;&lt;/iframe&gt;
&lt;/div&gt;
&lt;/p&gt;
&lt;h1 id=&#34;高远球压制战术的反制措施&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#高远球压制战术的反制措施&#34;&gt;#&lt;/a&gt; 高远球压制战术的反制措施&lt;/h1&gt;
&lt;p&gt;高远球反复落点或反复后场的对峙手段学习自陈金老师：&lt;/p&gt;
&lt;p&gt;
&lt;div style=&#34;position: relative; width: 100%; height: 0; padding-bottom: 75%;&#34;&gt;
    &lt;iframe src=&#34;//player.bilibili.com/player.html?isOutside=true&amp;aid=1352091436&amp;bvid=BV1m6421F7Lu&amp;cid=1478961459&amp;p=1&amp;autoplay=0&#34; scrolling=&#34;no&#34; border=&#34;0&#34; frameborder=&#34;no&#34; framespacing=&#34;0&#34; allowfullscreen=&#34;true&#34; style=&#34;position:absolute; height: 100%; width: 100%;&#34;&gt;&lt;/iframe&gt;
&lt;/div&gt;
&lt;br /&gt;
 总结关键点为：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;加强一致性，提高动作隐蔽性。&lt;/li&gt;
&lt;li&gt;回快速的平高球。&lt;/li&gt;
&lt;li&gt;加入中场杀球或中场软压。&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;抓推技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#抓推技术&#34;&gt;#&lt;/a&gt; 抓推技术&lt;/h1&gt;
&lt;p&gt;抓推技术学习自刘辉教练：&lt;/p&gt;
&lt;p&gt;
&lt;div style=&#34;position: relative; width: 100%; height: 0; padding-bottom: 75%;&#34;&gt;
    &lt;iframe src=&#34;//player.bilibili.com/player.html?isOutside=true&amp;aid=524989120&amp;bvid=BV17M411E7bL&amp;cid=1023628492&amp;p=1&amp;autoplay=0&#34; scrolling=&#34;no&#34; border=&#34;0&#34; frameborder=&#34;no&#34; framespacing=&#34;0&#34; allowfullscreen=&#34;true&#34; style=&#34;position:absolute; height: 100%; width: 100%;&#34;&gt;&lt;/iframe&gt;
&lt;/div&gt;
&lt;br /&gt;
 这个视频是如何利用吊远网球进行远网抓推。&lt;/p&gt;
&lt;p&gt;
&lt;div style=&#34;position: relative; width: 100%; height: 0; padding-bottom: 75%;&#34;&gt;
    &lt;iframe src=&#34;//player.bilibili.com/player.html?isOutside=true&amp;aid=394112885&amp;bvid=BV1Ed4y1J7KE&amp;cid=1000547893&amp;p=1&amp;autoplay=0&#34; scrolling=&#34;no&#34; border=&#34;0&#34; frameborder=&#34;no&#34; framespacing=&#34;0&#34; allowfullscreen=&#34;true&#34; style=&#34;position:absolute; height: 100%; width: 100%;&#34;&gt;&lt;/iframe&gt;
&lt;/div&gt;
&lt;br /&gt;
 这个是视频则是直接介绍进行远网抓推的关键。&lt;/p&gt;
&lt;p&gt;
&lt;div style=&#34;position: relative; width: 100%; height: 0; padding-bottom: 75%;&#34;&gt;
    &lt;iframe src=&#34;//player.bilibili.com/player.html?isOutside=true&amp;aid=113209046537095&amp;bvid=BV1xmxFewEPF&amp;cid=26030244616&amp;p=1&amp;autoplay=0&#34; scrolling=&#34;no&#34; border=&#34;0&#34; frameborder=&#34;no&#34; framespacing=&#34;0&#34; allowfullscreen=&#34;true&#34; style=&#34;position:absolute; height: 100%; width: 100%;&#34;&gt;&lt;/iframe&gt;
&lt;/div&gt;
&lt;br /&gt;
 这个视频则是讲解一些抓推的特殊情况。&lt;/p&gt;
&lt;h1 id=&#34;启动步&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#启动步&#34;&gt;#&lt;/a&gt; 启动步&lt;/h1&gt;
&lt;p&gt;启动步启蒙老师是李宇轩教练。&lt;br /&gt;

&lt;div style=&#34;position: relative; width: 100%; height: 0; padding-bottom: 75%;&#34;&gt;
    &lt;iframe src=&#34;//player.bilibili.com/player.html?isOutside=true&amp;aid=113610021935044&amp;bvid=BV1A8iyYZEK6&amp;cid=27220643779&amp;p=1&amp;autoplay=0&#34; scrolling=&#34;no&#34; border=&#34;0&#34; frameborder=&#34;no&#34; framespacing=&#34;0&#34; allowfullscreen=&#34;true&#34; style=&#34;position:absolute; height: 100%; width: 100%;&#34;&gt;&lt;/iframe&gt;
&lt;/div&gt;
&lt;br /&gt;
 从这个视频在启动步上有了启蒙，使我增加了对步伐的重视度。&lt;/p&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;h1 id=&#34;项目说明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#项目说明&#34;&gt;#&lt;/a&gt; 项目说明&lt;/h1&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;背景&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;这个小项目实践是一年前博主大二学习深度学习写的。现在整理代码和博客，顺便放到这里。&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;设计要求&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;要求采集训练数据，搭建网络模型，设计训练设置，模型经过训练能够实现手写数字的生成，以达到学习实验基本流程的目的。&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;配置&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;Pycharm、RTX3050 Laptop（4G）、python。&lt;/p&gt;
&lt;p&gt;由于是一个用于练习的小项目，其实对虚拟环境中的库版本要求不是很高，只要装了基本上没有什么太大的问题。&lt;/p&gt;
&lt;div class=&#34;note danger&#34;&gt;
&lt;p&gt;待更新。&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;效果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#效果&#34;&gt;#&lt;/a&gt; 效果&lt;/h1&gt;

 &lt;link rel=&#34;stylesheet&#34; class=&#34;aplayer-secondary-style-marker&#34; href=&#34;\assets\css\APlayer.min.css&#34;&gt;&lt;script src=&#34;\assets\js\APlayer.min.js&#34; class=&#34;aplayer-secondary-script-marker&#34;&gt;&lt;/script&gt;&lt;h1 id=&#34;项目说明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#项目说明&#34;&gt;#&lt;/a&gt; 项目说明&lt;/h1&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;项目背景&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;本项目为编译原理课设作业之一，通过输入给定的正则表达式，构建该正则表达式对应的非确定有穷自动机 NFA，然后根据该 NFA 转换为确定有穷自动机 DFA，最后对该确定有穷自动机 DFA 最小化为最简 DFA。得到最简 DFA 后，可以对用户输入的符号串进行判断是否符合正则表达式的要求。&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;数据结构&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;本实验使用的数据结构以及相关定义如下：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;状态转换表 &lt;code&gt;data&lt;/code&gt;  用邻接表存储。&lt;/li&gt;
&lt;li&gt;用集合存储最小化 DFA 过程中因子集划分法产生的状态组。&lt;/li&gt;
&lt;li&gt;用栈存储正则表达式中的操作符。&lt;/li&gt;
&lt;li&gt;正则表达式中的空串用空格代表。&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;实验配置&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;VSCode，c 语言。&lt;/p&gt;
&lt;h1 id=&#34;源码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#源码&#34;&gt;#&lt;/a&gt; 源码&lt;/h1&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;figcaption data-lang=&#34;c&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&amp;lt;stdio.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&amp;lt;string.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&amp;lt;stdlib.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;define&lt;/span&gt; &lt;span class=&#34;token macro-name&#34;&gt;MAXN&lt;/span&gt; &lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token number&#34;&gt;1000&lt;/span&gt;       &lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;//! 定义最大数量&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;define&lt;/span&gt; &lt;span class=&#34;token macro-name&#34;&gt;Visible_letter_count&lt;/span&gt; &lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Visible_letter_max &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt; Visible_letter_min &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;// 可视字符数量&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;define&lt;/span&gt; &lt;span class=&#34;token macro-name&#34;&gt;Visible_letter_min&lt;/span&gt; &lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token number&#34;&gt;32&lt;/span&gt;       &lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;// 可视字符最小值&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;define&lt;/span&gt; &lt;span class=&#34;token macro-name&#34;&gt;Visible_letter_max&lt;/span&gt; &lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token number&#34;&gt;126&lt;/span&gt;      &lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;// 可视字符最大值&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;char&lt;/span&gt; kong &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token char&#34;&gt;&#39; &#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;//! 空格代表空串&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;//-a-&gt;to&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;NODE&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; to&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;//1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;char&lt;/span&gt; a&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;//a&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;NODE&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;FA&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;//! 用结构体定义自动机 FA&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; n&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; BEGIN&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;//!n 为节点个数（包括空节点），BEGIN 为初态&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; ENDS&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;MAXN&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;100&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; len_ENDS&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;//! 定义终态集数组，以及数组长度&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    NODE data&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;MAXN&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;MAXN&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;      &lt;span class=&#34;token comment&#34;&gt;//!data 记录状态转换&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-nu